INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (317, 'web', 'Missing accessible name for image links', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are image links that do not have an accessible name. Examples include:<br />\n- The &quot;SSSSS&quot; image links under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; image links under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; image links under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, screen reader users will not be able to understand the purpose or destination of these image links, making navigation and interaction difficult.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide a complete and descriptive textual description that clearly describes the purpose of these image links. Ensure that the textual description of image links with different functionality is unique. Add descriptive label for the image links using the aria-label attribute.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.1.1\",\"wcagsuccesscriterianame\":\"Non-Text Content\",\"gigw30\":\"5.2.1\",\"is17802\":\"9.1.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (318, 'web', 'Inappropriate accessible name for image links', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are image links with inappropriate accessible names. Examples include:<br />\n- The &quot;SSSSS&quot; image links under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; image links under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; image links under &quot;SSSSS&quot; section. <br />\n<br />\nAs a result, users of assistive technologies may receive unclear or misleading information about the link&#039;s function or destination, leading to confusion or misnavigation.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide a complete and descriptive textual description that clearly describes the purpose of these image links. Ensure that the textual description of image links with different functionality is unique. Add descriptive label for the image links using the aria-label attribute.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.1.1\",\"wcagsuccesscriterianame\":\"Non-Text Content\",\"gigw30\":\"5.2.1\",\"is17802\":\"9.1.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (319, 'web', 'Missing accessible name for image buttons', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are image buttons that do not have an accessible name. Examples include:<br>\n- The \"SSSSS\" image buttons under \"SSSSS\" section.<br>\n- The \"SSSSS\" image buttons under \"SSSSS\" section.<br>\n- The \"SSSSS\" image buttons under \"SSSSS\" section.<br>\n<br>\nAs a result, screen reader users will be unable to identify the purpose of these buttons.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that appropriate textual description for the image buttons is provided and it completely describes the purpose of these buttons.<br>\nThe textual description can be provided by adding a visually hidden text using CSS within the button element.<br>\nAlternatively, use the \"aria-label\" attribute on the button element to provide a textual description.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"wcagsuccesscriteria\":\"1.1.1\",\"wcagsuccesscriterianame\":\"Non-text Content\",\"wcagsuccesscriterialevel\":\"A\",\"gigw30\":\"5.2.1\",\"is17802\":\"9.1.1.1\",\"severity\":\"Critical\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (320, 'web', 'Inappropriate accessible name for image buttons', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are image buttons with inappropriate accessible names. Examples include:<br />\n- The &quot;SSSSS&quot; image buttons under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; image buttons under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; image buttons under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, incorrect or unclear labels can mislead users of assistive technologies, possibly causing them to activate unintended functions.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that appropriate textual description for the image buttons is provided and it completely describes the purpose of these buttons.<br />\nThe textual description can be provided by adding a visually hidden text using CSS within the button element.<br />\nAlternatively, use the &quot;aria-label&quot; attribute on the button element to provide a textual description.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.1.1\",\"wcagsuccesscriterianame\":\"Non-Text Content\",\"gigw30\":\"5.2.1\",\"is17802\":\"9.1.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (321, 'web', 'Missing alternative text for informative image', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are informative images that do not have an alternative text. Examples include:<br />\n- The &quot;SSSSS&quot; images under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; images under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; images under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, screen reader users will miss out on important visual content conveyed by these images, affecting their understanding of the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide appropriate and complete alternative text for the informative image. Ensure that the alternative is completely describing the purpose of the image.<br />\n<br />\nFor &lt;img&gt; elements, add &quot;alt&quot; attribute with the short description of the image.<br />\n<br />\nFor SVG images, apply the following changes:<br />\n• Add a short description of the image by using the &lt;title&gt; element.<br />\n• Define the &lt;title&gt; within the &lt;svg&gt; tag as the first child element.<br />\n• Specify “aria-labelledby” and role=&quot;img&quot; attributes on the &lt;svg&gt; element and reference it via the “id” attribute of the &lt;title&gt; elements respectively.<br />\n• Alternatively, &quot;aria-label&quot; attribute can be used instead of &quot;ara-labelledby&quot; attribute.<br />\n<br />\nFor font icons (&lt;i&gt; or &lt;span&gt;):<br />\n• provide role=&quot;img&quot; and description of the image by using &quot;aria-label&quot; attribute.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.1.1\",\"wcagsuccesscriterianame\":\"Non-Text Content\",\"gigw30\":\"5.2.1\",\"is17802\":\"9.1.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (322, 'web', 'Missing textual description for complex images', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are complex images that do not have a sufficiently descriptive textual description. Examples include:<br />\n- The &quot;SSSSS&quot; images under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; images under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; images under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, users relying on assistive technologies will not receive enough information to interpret charts, graphs, or diagrams, impacting comprehension and decision-making.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that complex images have both, a short description which gives a title to the image, as well as a long description which explains in detail all the essential information conveyed by the image. The long description can contain headings, paragraphs, and tables as per requirement.<br />\n<br />\nFor example,<br />\nIn case of complex image defined using &lt;img&gt; tag, use a suitable method from the following:<br />\n1. Using text link for long description.<br />\n• Provide a short description for the image using the “alt” attribute.<br />\n• Provide a text link adjacent to the image that contains a complete and detailed text description of the image. The text link can refer to a separate web page or a section of the same web page.<br />\n• In addition to this, the image can be associated with the link by defining the image and link within a &lt;figure&gt; element with role=&quot;group&quot;. Define the the link text within the &lt;figcaption&gt; element.<br />\n<br />\n2. Using &quot;aria-describedby&quot; association for long description<br />\n• Provide a short description for the image using the “alt” attribute.<br />\n• Use the &quot;aria-describedby&quot; attribute on the &lt;img&gt; element. Associate the existing description about the complex image present on the page by passing its &quot;id&quot; value in in the &quot;aria-describedby&quot; attribute.<br />\n<br />\nIn case of complex image defined using &lt;svg&gt;, apply the following changes:<br />\n• Provide a short description of the image by using the &lt;title&gt; element. <br />\n• Provide a detailed description of the image by using the &lt;desc&gt; element.<br />\n• Define the &lt;title&gt; and &lt;desc&gt; within the &lt;svg&gt; tag as the first child elements.<br />\n• Specify “aria-labelledby” and “aria-describedby” attributes on the &lt;svg&gt; element and reference it via the “id” attributes of the &lt;title&gt; and &lt;desc&gt; elements respectively.<br />\n<br />\nNote: Association using &quot;aria-describedby&quot; does not communicate the structural information to assistive technologies. The information is presented as a single string.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.1.1\",\"wcagsuccesscriterianame\":\"Non-Text Content\",\"gigw30\":\"5.2.1\",\"is17802\":\"9.1.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (323, 'web', 'Inappropriate alternative text for informative images', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are informative images with an inappropriate alternative text. Examples include:<br />\n- The &quot;SSSSS&quot; images under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; images under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; images under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, misleading or vague alternative text can confuse users relying on screen readers, leading to misunderstandings about the image’s meaning.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide appropriate and complete alternative text for the informative image. Ensure that the alternative is completely describing the purpose of the image.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.1.1\",\"wcagsuccesscriterianame\":\"Non-Text Content\",\"gigw30\":\"5.2.1\",\"is17802\":\"9.1.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (324, 'web', 'Unnecessary alternative text for decorative images', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are decorative images that do not have an &#039;alt&#039; attribute or have an unnecessary alternative text. Examples include:<br />\n- The &quot;SSSSS&quot; decorative images under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; decorative images under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; decorative images under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, these images may be read aloud by screen readers unnecessarily, adding noise and distraction, which hampers efficient navigation.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that decorative images are hidden from screen readers. Apply the following changes:<br />\n• If image is coded with &lt;img&gt; element, make sure that the alt attribute is empty. For e.g., alt=&quot;&quot;<br />\n• If images are coded with &lt;i&gt;, &lt;span&gt;, or &lt;svg&gt; elements, then aria-hidden=&quot;true&quot; should be added to the source of these elements.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.1.1\",\"wcagsuccesscriterianame\":\"Non-Text Content\",\"gigw30\":\"5.2.1\",\"is17802\":\"9.1.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (325, 'web', 'Redundant image and textual link with redundant alt text', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are image and text links with similar or inappropriate accessible names that point to the same destination and are coded with separate &lt;a&gt; elements. Examples include:<br />\n- The &quot;SSSSS&quot; links under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; links under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; links under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, redundant or inconsistent accessible names may confuse screen reader users or cause them to think the links serve different purposes, increasing cognitive load.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the image and text link that point to the same destination are combined into a single link as a link block.<br />\nApply the following changes:<br />\n• Define the image and the link text within a single &lt;a&gt; element instead of separate &lt;a&gt; elements.<br />\n• Ideally alternate text must be provided to all image links using the &quot;alt&quot; attribute. In this instance, since the image and the textual link point to an identical destination page, use an empty ‘alt’ attribute. <br />\n• Use CSS if necessary to maintain the presentation of the content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.1.1\",\"wcagsuccesscriterianame\":\"Non-Text Content\",\"gigw30\":\"5.2.1\",\"is17802\":\"9.1.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (326, 'web', 'Missing alternatives for CAPTCHAs', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are CAPTCHAs that do not have any alternative verification methods. Examples include:<br />\n- The &quot;SSSSS&quot; CAPTCHA under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; CAPTCHA under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; CAPTCHA under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, users with visual, cognitive, or motor disabilities may be unable to complete CAPTCHA challenges, preventing them from accessing content or submitting forms.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that CAPTCHA implementations are accessible by providing alternative verification methods for users who may have difficulty with visual challenges. Consider offering audio CAPTCHAs or simpler question-based alternatives to accommodate diverse needs. Additionally, clearly label the CAPTCHA field and provide instructions to help users understand the verification process.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.1.1\",\"wcagsuccesscriterianame\":\"Non-Text Content\",\"gigw30\":\"5.2.1\",\"is17802\":\"9.1.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (327, 'web', 'Missing alternative for video-only content', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are video-only or audio-only content that do not have a text transcript. Examples include:<br />\n- The &quot;SSSSS&quot; media under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; media under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; media under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, users who are deaf, hard of hearing, or blind will not have access to the media content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide information using one of the alternative methods given below:<br />\n1. Provide a text transcript for the video and ensure that the description is accurate. The text transcript can be displayed on a separate page and a link/button can be provided beside the video to help users access the transcript. This will ensure that the video content is accessible for visual impairment users and deaf-blind users. <br />\n2. Include the information in the form of an audio track that can be added to the video. This will ensure that the video content is accessible to visual impairment users.<br />\n<br />\nNote: We would recommend providing a text transcript for the video for the benefit of deaf-blind users.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment, Hearing Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.2.1\",\"wcagsuccesscriterianame\":\"Audio-only and Video-only (Prerecorded)\",\"gigw30\":\"5.2.2\",\"is17802\":\"9.1.2.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (328, 'web', 'Missing captions for the video', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are videos (which include audio) that do not have synchronized captions. Examples include:<br />\n- The &quot;SSSSS&quot; videos under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; videos under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; videos under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, deaf and hard-of-hearing users will miss important spoken information.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Add synchronized captions for all videos whose audio content communicates information not included in the visual component.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Hearing Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.2.2\",\"wcagsuccesscriterianame\":\"Captions (Prerecorded)\",\"gigw30\":\"5.2.3\",\"is17802\":\"9.1.2.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (329, 'web', 'Missing text transcript for the video', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are videos (which include audio) that do not have a text transcript. Examples include:<br />\n- The &quot;SSSSS&quot; videos under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; videos under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; videos under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, users who cannot access audio due to hearing disability or technical limitations may miss critical content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide text transcripts for the video and ensure that the description is accurate. The text transcript can be displayed on a separate page and a link/button can be provided beside the video to help users access the transcript.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.2.3\",\"wcagsuccesscriterianame\":\"Audio Description or Media Alternative (Prerecorded)\",\"gigw30\":\"5.2.4\",\"is17802\":\"9.1.2.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (330, 'web', 'Missing captions for the live video', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are live videos that do not have captions. Examples include:<br />\n- The &quot;SSSSS&quot; live streams under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; live streams under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; live streams under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, users who are deaf or hard of hearing are excluded from the live information being presented.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure captions are provided for all prerecorded audio content in synchronized media, except when the media is a media alternative for text and is clearly labeled as such.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Hearing Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.2.4\",\"wcagsuccesscriterianame\":\"Captions (Live)\",\"gigw30\":\"5.2.5\",\"is17802\":\"9.1.2.4\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (331, 'web', 'Missing audio description for the video', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are videos that do not have an audio description. Examples include:<br />\n- The &quot;SSSSS&quot; videos under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; videos under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; videos under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, blind or visually impaired users will miss critical visual information that is not conveyed through the audio.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Add audio descriptions in the videos wherever the visual content is conveyed to ensure that visual impairment and learning impairment users can listen to the audio description and understand the content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.2.5\",\"wcagsuccesscriterianame\":\"Audio Description (Prerecorded)\",\"gigw30\":\"5.2.6\",\"is17802\":\"9.1.2.5\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (332, 'web', 'Heading mark-up used unnecessarily', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is text that does not describe any contents below it that is marked up with a heading unnecessarily. Examples include:<br />\n- The &quot;SSSSS&quot; text headings under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; text headings under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; text headings under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, screen reader users may get confused or frustrated by the inappropriate use of headings.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Remove the heading mark-up from the mentioned content and code it using the &lt;p&gt; element. If required, use CSS to maintain the presentation of the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (333, 'web', 'Inappropriate heading structure', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are headings that cause inappropriate heading structure. Examples include:<br />\n- The &quot;SSSSS&quot; headings under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; headings under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; headings under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, users navigating via headings may experience a disjointed or confusing content hierarchy.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Use heading levels as per specification such as &lt;h1&gt; should be followed by &lt;h2&gt;, &lt;h3&gt; and so on. It is recommended that the discussed issue be addressed as screen reader users rely on headings heavily to understand the page structure.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (334, 'web', 'Missing heading mark-up', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are text contents that are missing heading markup. Examples include:<br />\n- The &quot;SSSSS&quot; text under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; text under &quot;SSSSS&quot; section.<br />\n- The &quot;SSSSS&quot; text under &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, screen reader users may not be able to efficiently navigate or understand the content structure.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Mark-up the mentioned text using appropriate HTML headings. In addition, use heading levels as per specification such as &lt;h1&gt; should be followed by &lt;h2&gt;, &lt;h3&gt; and so on.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (335, 'web', 'Missing h1 heading mark-up', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>The page lacks heading level 1 markup that describes the page.<br />\n<br />\nAs a result, users may not immediately understand the main purpose or topic of the page when using assistive technologies.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide descriptive text using &lt;h1&gt; tag. Place this text off-screen using CSS such that it will hide the text visually but available for screen reader users.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (336, 'web', 'Multiple H1 headings defined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are multiple &lt;h1&gt; used on the page. Examples include:<br />\n- The &quot;SSSSS&quot; heading<br />\n- The &quot;SSSSS&quot; heading<br />\n- The &quot;SSSSS&quot; heading<br />\n<br />\nAs a result, this creates confusion for screen reader users who rely on heading structure to understand the organization of the content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>It is recommended to use only one heading with level 1 on a page.<br />\n<br />\nApply the following changes:<br />\n• Keep the &lt;h1&gt; heading for only the heading that described the purpose of the page.<br />\n• Mark up the other headings using &lt;h2&gt;, &lt;h3&gt;, and so on elements.<br />\n• Use CSS to maintain the presentation of the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (337, 'web', 'Empty heading found in page source code', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are empty headings present in the source code of the page. Examples include:<br />\n- An empty &lt;h2&gt; tag above the &quot;SSSSS&quot; sections.<br />\n- An empty &lt;h3&gt; tag above the &quot;SSSSS&quot; sections.<br />\n<br />\nAs a result, keyboard and screen reader users may be confused navigating via heading shortcuts, as these empty headings provide no meaningful information.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Remove the empty heading elements from the source code of the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (338, 'web', 'Missing list mark-up', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are contents that display related information that do not use appropriate list markup. Examples include:<br />\n- The text such as &quot;SSSSSS&quot;, &quot;SSSSSS&quot;, &quot;SSSSSS&quot; and so on under the &quot;SSSSS&quot; section.<br />\n- The text such as &quot;SSSSSS&quot;, &quot;SSSSSS&quot;, &quot;SSSSSS&quot; and so on under the &quot;SSSSS&quot; section.<br />\n- The text such as &quot;SSSSSS&quot;, &quot;SSSSSS&quot;, &quot;SSSSSS&quot; and so on under the &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, screen reader users may not perceive related items as a group, reducing comprehension and making content harder to follow.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Use appropriate list mark-up, such as &lt;ul&gt; and &lt;li&gt; or &lt;ol&gt; and &lt;li&gt; to identify related information. In addition, consider applying styles to maintain the visual presentation of a web page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (339, 'web', 'List mark-up used unnecessarily', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are contents that do not display any related information but use list markup. Examples include:<br />\n- The &quot;SSSSSS&quot; text under the &quot;SSSSS&quot; section wrapped in a &lt;ul&gt; element.<br />\n- The &quot;SSSSSS&quot; text under the &quot;SSSSS&quot; section wrapped in a &lt;ul&gt; element.<br />\n- The &quot;SSSSSS&quot; text under the &quot;SSSSS&quot; section wrapped in a &lt;ul&gt; element.<br />\n<br />\nAs a result, screen reader users may be misled into expecting multiple list items, causing confusion about the content structure.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Remove the list mark-up from the mentioned content and code it using &lt;p&gt; element. CSS can be used to maintain the presentation of the page if required.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (340, 'web', 'List mark-up used incorrectly', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are &lt;li&gt; elements without a &lt;ul&gt; parent element. Examples include:<br />\n- &lt;li&gt; tags used in the &quot;SSSSS&quot; section without any enclosing list container.<br />\n<br />\nAs a result, assistive technology may produce confusing announcements due to broken semantic structure.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Use appropriate list mark-up, such as &lt;ul&gt; and &lt;li&gt; to identify related information. In addition, if required apply styles to maintain the visual presentation of the web page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (341, 'web', 'Quote not marked-up as a blockquote', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are quotations that are not marked up programmatically using &lt;blockquote&gt; tag. Examples include:<br />\n- A &quot;SSSSS&quot; text in the &quot;SSSSS&quot; section<br />\n- A &quot;SSSSS&quot; text in the &quot;SSSSS&quot; section<br />\n- A &quot;SSSSS&quot; text in the &quot;SSSSS&quot; section.<br />\n<br />\nAs a result, screen reader users cannot recognize the text as a quotation, losing contextual understanding.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>All quotations must be marked up using the &lt;blockquote&gt; and &lt;cite&gt; element.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (342, 'web', 'Use of multiple <header> landmark tags', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are multiple &lt;header&gt; landmarks used on the page.<br />\n<br />\nAs a result, screen reader users may be confused by duplicate landmark regions, reducing navigation efficiency.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Remove the &lt;header&gt; element provided in the main content area.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (343, 'web', 'Decorative separator announced by screen reader', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are separators used for decorative purposes but announced by screen readers. Examples include:<br />\n- The &lt;hr&gt; tag above the &quot;SSSSS&quot; heading<br />\n- The &lt;hr&gt; tag above the &quot;SSSSS&quot; heading<br />\n- The &lt;hr&gt; tag above the &quot;SSSSS&quot; heading<br />\n<br />\nAs a result, screen reader users may receive unnecessary announcements that disrupt the user experience.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>The horizontal bar should be defined using CSS instead of &lt;hr&gt; tag to ensure that it is not identified by a screen reader. Define a border via CSS class to include a horizontal line separator. <br />\nAlternatively, if &lt;hr&gt; tag is used, specify role=&quot;presentation&quot; to &lt;hr&gt; tag.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (344, 'web', 'Content defined outside landmark region', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is content placed outside appropriate landmark regions. Examples include:<br />\n- The &quot;SSSSS&quot; content placed out side the &lt;main&gt; landmark<br />\n- The &quot;SSSSS&quot; content placed out side the &lt;header&gt; landmark<br />\n- The &quot;SSSSS&quot; content placed out side the &lt;footer&gt; landmark<br />\n<br />\nAs a result, screen reader users may miss critical content that is not within navigable landmarks.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that all the contents are coded within the appropriate landmark. For example, header contents should be coded within &lt;header&gt;, main content should be coded within the &lt;main&gt; element and so on.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (345, 'web', 'Data table not programmatically defined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are tables that are not programmatically defined. Examples include:<br />\n- The table under the &quot;SSSSS&quot; section<br />\n- The table under the &quot;SSSSS&quot; section<br />\n- The table under the &quot;SSSSS&quot; section<br />\n<br />\nAs a result, screen reader users cannot understand or navigate the tabular relationship of content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Utilized table mark-up, such as &lt;table&gt;, &lt;tr&gt;, &lt;th&gt;, &lt;td&gt;,  and so on to present the content as a data table.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (346, 'web', 'Table headers not programmatically defined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are table headers that are not properly defined with the &lt;th&gt; element. Examples include:<br />\n- The &quot;SSSSSS&quot; table header<br />\n- The &quot;SSSSSS&quot; table header<br />\n- The &quot;SSSSSS&quot; table header<br />\n<br />\nAs a result, screen reader users have difficulty associating data cells with their headers, impacting comprehension.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Use &lt;th&gt; tags to identify headers. Additionally, use scope=&quot;col&quot; and scope=&quot;row&quot; to defined the coloum and row headers respectively.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (347, 'web', 'Layout table announced for screen reader users', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are layout tables that are unnecessarily announced to screen reader users. Examples include:<br />\n- The table under the &quot;SSSSS&quot; section<br />\n- The table under the &quot;SSSSS&quot; section<br />\n- The table under the &quot;SSSSS&quot; section<br />\n- The table under the &quot;SSSSS&quot; section<br />\n<br />\nAs a result, screen reader users experience extra noise, reducing clarity when navigating the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide role=&quot;presentation&quot; to the &lt;table&gt; tag of the layout table.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (348, 'web', 'Missing explicit association of form fields', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are form fields that are missing explicit label associations. Examples include:<br />\n- The &quot;SSSSS&quot; label is not associated with its input field<br />\n- The &quot;SSSSS&quot; label is not associated with its input field<br />\n- The &quot;SSSSS&quot; label is not associated with its input field<br />\n<br />\nAs a result, screen reader users may not understand the purpose of the field, making form completion difficult or impossible.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Use ‘for’ and ‘id’ attributes to associate labels with their respective form fields. Ensure that the value of ‘for’ attribute of the label exactly matches the value of ‘id’ attribute of the form field.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (349, 'web', 'Missing grouping of form controls', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are form controls that are not properly grouped. Examples include:<br />\n- The &quot;SSSSS&quot; group under the &quot;SSSSS&quot; section is not marked up using &lt;fieldset&gt; and &lt;legend&gt;<br />\n- The &quot;SSSSS&quot; group under the &quot;SSSSS&quot; section is wrapped within &lt;fieldset&gt; element but lacks the &lt;legend&gt; element<br />\n<br />\nAs a result, screen reader users may not understand the relationship between grouped options, leading to incorrect selections.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Include the group name within &lt;legend&gt; element. Use &lt;fieldset&gt;and &lt;legend&gt; elements to group the instruction and radio buttons. Make sure that &lt;legend&gt; element is the first child element of the &lt;fieldset&gt; element.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (350, 'web', 'Additional information not associated', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are additional information that are not associated with the respective elements. Examples include:<br />\n- Instructional text for the &quot;SSSSS&quot; input field under the &quot;SSSSS&quot; section is not associated with the &quot;SSSSS&quot; input field.<br />\n- Additional information such as &quot;SSSSS&quot;, &quot;SSSSS&quot;, and so on are no associated with the &quot;SSSSS&quot; link<br />\n- Additional information such as &quot;SSSSS&quot;, &quot;SSSSS&quot;, and so on are no associated with the &quot;SSSSS&quot; button<br />\n<br />\nAs a result, users relying on assistive technologies may miss key instructions, leading to errors while completing the form.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Add &quot;aria-describedby&quot; attribute to the form field.<br />\n• Reference the &quot;id&quot; value of the element used to display the instruction text in the &quot;aria-describedby&quot; attribute.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.3.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (351, 'web', 'Inaccurate reading order', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is page content that does not follow a logical reading order. The following is the incorrect reading order:<br />\n1. The &quot;SSSSS&quot; text under the &quot;SSSSS&quot; heading<br />\n2. The &quot;SSSSS&quot; text under the &quot;SSSSS&quot; heading<br />\n3. The &quot;SSSSS&quot; text under the &quot;SSSSS&quot; heading<br />\n4. The &quot;SSSSS&quot; text under the &quot;SSSSS&quot; heading<br />\n<br />\nAs a result, screen reader users may experience disorientation or misinterpret the page structure.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Place the content of webpages in correct meaningful sequence in the source code. Move the content in the page source in the below mentioned order. CSS can be used to maintain the presentation of the page.<br />\n<br />\nExpected reading order:<br />\n1. The &quot;SSSSS&quot; text under the &quot;SSSSS&quot; heading<br />\n2. The &quot;SSSSS&quot; text under the &quot;SSSSS&quot; heading<br />\n3. The &quot;SSSSS&quot; text under the &quot;SSSSS&quot; heading<br />\n4. The &quot;SSSSS&quot; text under the &quot;SSSSS&quot; heading</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.2\",\"wcagsuccesscriterianame\":\"Meaningful Sequence\",\"gigw30\":\"5.2.8\",\"is17802\":\"9.1.3.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (352, 'web', 'Unnecessary use of sensory characteristics', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is content that relies solely on sensory characteristics to convey meaning. Examples include:<br />\n- The instruction &quot;Click the red SSSSS&quot; present in the SSSSS section relies only on color to convey meaning.<br />\n<br />\nAs a result, blind or colorblind users may not perceive the intended instruction, causing functional barriers.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure instructions provided for understanding and operating content do not rely solely on sensory characteristics of components such as shape, color, size, visual location, orientation, or sound.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Color Blindness, Visual Impairment,\\nHearing Impariment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.3\",\"wcagsuccesscriterianame\":\"Sensory Characteristics\",\"gigw30\":\"5.2.9\",\"is17802\":\"9.1.3.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (353, 'web', 'Content not available in portrait mode', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is content that is not available or displayed correctly in portrait and/or landscape mode. Examples include:<br />\n- The &quot;SSSSS&quot; component present in the SSSSS section gets cut off or misaligned when switching to landscape view.<br />\n<br />\nAs a result, users with mobility or visual needs who depend on specific orientations may lose access to key content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Use CSS media queries to ensure that all the page content is available in both landscape and portrait orientation. Use media query &quot;@media screen and (orientation: portrait)&quot; to define how the mentioned table will be displayed in both the orientations.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.3.4\",\"wcagsuccesscriterianame\":\"Orientation\",\"gigw30\":\"5.2.10\",\"is17802\":\"9.1.3.4\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (354, 'web', 'Purpose of input field not identified programmatically', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are common input fields with inappropriate autocomplete values or missing autocomplete attributes. Examples include:<br />\n- The &quot;SSSSS&quot; input field present in the SSSSS section lacks appropriate autocomplete value such as autocomplete=&quot;email&quot;.<br />\n<br />\nAs a result, users with motor impairments or cognitive limitations may face difficulties filling out forms efficiently.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Use HTML 5.2 autocomplete attribute to add token values for common input fields. This will improve the browser&#039;s auto fill feature as well as can be used by plug-ins to fill in the details for users with mobility and cognitive impairments. <br />\nFor more information on how to implement this, refer:<br />\nhttps://www.w3.org/WAI/WCAG21/Techniques/html/H98</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment,\\nCognitive Impariment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.3.5\",\"wcagsuccesscriterianame\":\"Identify Input Purpose\",\"gigw30\":\"5.2.11\",\"is17802\":\"9.1.3.5\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (355, 'web', 'Color alone used to convey selected state', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are instances where only color is used to indicate the selected state. Examples include:<br />\n- The &quot;SSSSS&quot; tab in the SSSSS section uses blue color to indicate the selected state while others are gray, without additional cues.<br />\n<br />\nAs a result, users with color blindness or low vision may not be able to identify the selected option.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>In the mentioned example along with color, use additional visual cues such as underline, bold, patterns, and so on to convey the selected state information.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Color Blindness\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.4.1\",\"wcagsuccesscriterianame\":\"Use of Color\",\"gigw30\":\"5.2.12\",\"is17802\":\"9.1.4.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (356, 'web', 'Color alone used to distinguish links', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are links that rely solely on color for differentiation. Examples include:<br />\n- The &quot;SSSSS&quot; link present in the SSSSS section is only differentiated by color and lacks underline or font weight styling.<br />\n<br />\nAs a result, users with color vision deficiencies or screen readers may not recognize the presence of links.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>To make it easy for all users to recognize links the best practice is to persistently underline them or provide any other visual cue such as formatting the text as bold or italic. If the above solution is not feasible, change the color of links so that they have a contrast ratio of at least 3:1 with the surrounding text. Moreover, it is best practice to ensure that the underline appears not only when the mouse is hovered over the links but also when the links receive the keyboard focus.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Color Blindness\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.4.1\",\"wcagsuccesscriterianame\":\"Use of Color\",\"gigw30\":\"5.2.12\",\"is17802\":\"9.1.4.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (357, 'web', 'Color alone used to distinguish links when contrast requirement is met and no visual cue on hover', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are links that do not have any visual cue on hover state and use color alone to distinguish them from the surrounding text. Examples include:<br />\n- The &quot;SSSSS&quot; link present in the SSSSS section only changes color on hover without any underline or bold style.<br />\n<br />\nAs a result,  users with color vision deficiencies may miss clickable elements and navigation paths.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>To make it easy for all users to recognize links the best practice is to persistently underline them. If the above solution is not feasible, ensure that the underline appears when the mouse hovers over the links and when the links receive the keyboard focus.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Color Blindness\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.4.1\",\"wcagsuccesscriterianame\":\"Use of Color\",\"gigw30\":\"5.2.12\",\"is17802\":\"9.1.4.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (358, 'web', 'No mechanism to control the auto playing audio/video', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is audio/video content that plays automatically for more than 3 seconds and does not have any mechanism to pause, stop, or hide it. Examples include:<br />\n- The &quot;SSSSS&quot; video present in the SSSSS section plays automatically and lacks controls to stop or pause it.<br />\n<br />\nAs a result, screen reader users and people with cognitive disabilities may experience distraction and difficulty focusing.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>If any audio on a Web page plays automatically for more than 3 seconds, either a mechanism is available to pause or stop the audio, or a mechanism is available to control audio volume independently from the overall system volume level.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability, Visual Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.4.2\",\"wcagsuccesscriterianame\":\"Audio Control\",\"gigw30\":\"5.2.13\",\"is17802\":\"9.1.4.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (359, 'web', 'Insufficient color contrast for text', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is text with insufficient color contrast. Examples include:<br />\n- &quot;SSSSS&quot; present in the SSSSS section has #SSSSSS as foreground and #SSSSSS as background with a contrast ratio of 3.5:1.<br />\n<br />\nAs a result, users with low vision may find the text hard to read or completely illegible.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>On all pages, ensure that each foreground/background color combination presents a contrast ratio of at least 4.5:1 for standard text.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Low Vision\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.4.3\",\"wcagsuccesscriterianame\":\"Contrast (Minimum)\",\"gigw30\":\"5.2.14\",\"is17802\":\"9.1.4.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (360, 'web', 'Content not available, overlaps, or cut off on 200% zoom', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is content that is cut off, overlaps, or not available at 1280x1024 with 200% browser zoom. Examples include:<br />\n- The &quot;SSSSS&quot; component in the SSSSS section overlaps with other content or disappears at 200% zoom.<br />\n<br />\nAs a result, low-vision users who zoom in may miss out on critical content or functionality.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the page content is displayed using relative units for text and container so that users can access the page with zoom settings turned on. At the minimum, the page layouts should support up to 200% zoom.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Low Vision\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.4.4\",\"wcagsuccesscriterianame\":\"Resize Text\",\"gigw30\":\"5.2.15\",\"is17802\":\"9.1.4.4\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (361, 'web', 'Image of text used', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are instances where images of text are used instead of actual text. Examples include:<br />\n- The &quot;SSSSS&quot; heading present in the SSSSS section is displayed as an image rather than actual text.<br />\n<br />\nAs a result, screen reader users cannot access the information and low-vision users cannot resize or adjust the text properly.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Avoid using images of text (except for logo types, maps, diagrams etc.). This ensures that the text is not pixilated when zoomed in. <br />\nThus, it is recommended to specify textual information as plain text and CSS styling can be used for formatting effects wherever needed.<br />\nFor more information, refer https://www.w3.org/WAI/tutorials/images/textual/</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Low Vision, Learning Disability\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.4.5\",\"wcagsuccesscriterianame\":\"Images of Text\",\"gigw30\":\"5.2.16\",\"is17802\":\"9.1.4.5\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (362, 'web', 'Content fails to reflow', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is content that is cut off, overlaps, or not available when page has viewport width of 320x256 CSS pixels. Examples include:<br />\n- The &quot;SSSSS&quot; content present in the SSSSS section becomes inaccessible or hidden in small screen resolution.<br />\n<br />\nAs a result, mobile users, especially those with vision impairments, may not be able to access essential content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that all the page content is visible when viewed at 320 * 256 viewport. Use relative units to define font and container sizes in CSS to ensure that page&#039;s content reflows correctly when viewed at 320 * 256 viewport. In addition, use CSS media queries to display web page content correctly when viewed using different devices, such as mobile phones, tablets and so on.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Low Vision\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.4.10\",\"wcagsuccesscriterianame\":\"Reflow\",\"gigw30\":\"5.2.17\",\"is17802\":\"9.1.4.10\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (363, 'web', 'Insufficient color contrast for informative image', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are informative images with insufficient color contrast. Examples include:<br />\n- The &quot;SSSSS&quot; image present in the SSSSS section has #SSSSSS as foreground and #SSSSSS as background with contrast ratio of 2.5:1.<br />\n<br />\nAs a result, users with visual impairments may not be able to understand key image-based information.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>For the key parts of all the informative images, ensure that the contrast between foreground, background or adjacent colors is 3:1 to make the image&#039;s information accessible for low vision and color-blind users.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Low Vision\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.4.11\",\"wcagsuccesscriterianame\":\"Non-text Contrast\",\"gigw30\":\"5.2.18\",\"is17802\":\"9.1.4.11\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (364, 'web', 'Insufficient color contrast for the borders of form controls', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are form controls with borders that lack sufficient contrast. Examples include:<br />\n- The border of &quot;SSSSS&quot; input field present in the SSSSS section has #SSSSSS as foreground and #SSSSSS as background with contrast ratio of 2.5:1.<br />\n<br />\nAs a result, low-vision users may struggle to locate the input field.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the color contrast for the foreground color of the borders of all form fields is 3:1 with the background color.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Low Vision\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.4.11\",\"wcagsuccesscriterianame\":\"Non-text Contrast\",\"gigw30\":\"5.2.18\",\"is17802\":\"9.1.4.11\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (365, 'web', 'Insufficient color contrast for focus indicators', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are focus indicators that do not meet the required contrast ratio. Examples include:<br />\n- The focus indicator of &quot;SSSSS&quot; input field present in the SSSSS section has #SSSSSS as foreground and #SSSSSS as background with contrast ratio of 2.5:1.<br />\n<br />\nAs a result, keyboard-only users may not be able to identify where their focus is on the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the color contrast of focus indicator for all user interface controls is 3:1 with the foreground and background color.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Low Vision\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.4.11\",\"wcagsuccesscriterianame\":\"Non-text Contrast\",\"gigw30\":\"5.2.18\",\"is17802\":\"9.1.4.11\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (366, 'web', 'Insufficient color contrast of user interface controls', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are user interface controls that do not meet the required contrast ratio. Examples include:<br />\n- &quot;SSSSS&quot; control present in the SSSSS section has #SSSSSS as foreground and #SSSSSS as background with a contrast ratio of 2.5:1.<br />\n<br />\nAs a result, users with low vision may not perceive the control clearly, making it hard to interact with.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the color contrast for the foreground border color of user interface controls is 3:1 with the background color.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Low Vision\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.4.11\",\"wcagsuccesscriterianame\":\"Non-text Contrast\",\"gigw30\":\"5.2.18\",\"is17802\":\"9.1.4.11\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (367, 'web', 'Text gets cut off, disappears, or overlaps when text spacing styles are applied', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is text that gets cut off, disappears, or overlaps when text spacing styles are applied. Examples include:<br />\n- The &quot;SSSSS&quot; paragraph in the SSSSS section overlaps with adjacent content when line height or letter spacing is increased.<br />\n<br />\nAs a result, users who adjust text spacing for better readability may face difficulty reading the content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Define the text and container sizes using percent (%), em and rem units. In addition, use relative units for defining CSS line-height, letter-spacing and so on properties and ensure that user&#039;s text spacing styles are not overridden.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Learning Disability\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.4.12\",\"wcagsuccesscriterianame\":\"Text Spacing\",\"gigw30\":\"5.2.19\",\"is17802\":\"9.1.4.12\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (368, 'web', 'Text spacing styles cannot be applied', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are instances where text spacing styles cannot be applied. Examples include:<br />\n- The &quot;SSSSS&quot; text present in the SSSSS section is in a fixed container that does not adapt to modified line or word spacing.<br />\n<br />\nAs a result, users with dyslexia or low vision may struggle to read such content due to lack of adaptability.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Define the text and container sizes using percent (%), em and rem units. In addition, use relative units for defining CSS line-height, letter-spacing and so on properties and ensure that user&#039;s text spacing styles are not overridden.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Learning Disability\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.4.12\",\"wcagsuccesscriterianame\":\"Text Spacing\",\"gigw30\":\"5.2.19\",\"is17802\":\"9.1.4.12\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (369, 'web', 'Additional content available on hover or focus not hoverable', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is additional content available on hover or focus that is not hoverable. Examples include:<br />\n- The &quot;SSSSS&quot; tooltip in the SSSSS section disappears when trying to move the mouse towards it.<br />\n<br />\nAs a result, users may not be able to access the full content if it vanishes during interaction.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Modify the scripts associated with the additional content to ensure that it remains visible when the mouse pointer is hovered over the content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Low Vision\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.4.13\",\"wcagsuccesscriterianame\":\"Content on Hover or Focus\",\"gigw30\":\"5.2.20\",\"is17802\":\"9.1.4.13\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (370, 'web', 'Additional content available on hover or focus not persistent', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is additional content available on hover or focus that is not persistent. Examples include:<br />\n- The &quot;SSSSS&quot; helper text in the SSSSS section only appears momentarily and does not remain visible during focus or hover.<br />\n<br />\nAs a result, users may miss important guidance or information that disappears too quickly.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Modify the scripts associated with the additional content to ensure that it remains persistently visible until user decides to dismiss the additional content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Low vision, Motor Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.4.13\",\"wcagsuccesscriterianame\":\"Content on Hover or Focus\",\"gigw30\":\"5.2.20\",\"is17802\":\"9.1.4.13\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (371, 'web', 'Additional content available on hover or focus not dismissible', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is additional content available on hover or focus that is not dismissible. Examples include:<br />\n- The &quot;SSSSS&quot; dialog in the SSSSS section appears on focus but cannot be closed using Escape or other methods.<br />\n<br />\nAs a result, users who rely on screen magnifiers or keyboard navigation may find it difficult to access other parts of the page if the hover content obscures surrounding elements and cannot be dismissed without a mouse.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide a mechanism to dismiss the additional content on pressing an Esc key.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Low vision, Motor Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"1.4.13\",\"wcagsuccesscriterianame\":\"Content on Hover or Focus\",\"gigw30\":\"5.2.20\",\"is17802\":\"9.1.4.13\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (372, 'web', 'Menu not operable with a keyboard', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are menus that are not focusable or operable with a keyboard. Examples include:<br />\n- The &quot;SSSSS&quot; navigation menu in the SSSSS section<br />\n- The &quot;SSSSS&quot; navigation menu in the SSSSS section<br />\n- The &quot;SSSSS&quot; navigation menu in the SSSSS section<br />\n<br />\nAs a result, keyboard-only users cannot navigate through the menu items, affecting usability.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Modify the scripts associated with menu button to ensure that the sub-menu links are expanded/collapsed below when user activates menu button using Enter or Space key and the sub-menu links are reachable for keyboard-only and screen reader users.<br />\n• Ensure that &#039;aria-expanded&#039; attribute is set to &#039;true&#039; in the source code of the menu button when user activates the button via scripting. The value of &#039;aria-expanded&#039; attribute must be updated as per user interaction to &#039;false&#039; in collapsed state and &#039;true&#039; in expanded state.<br />\n<br />\nAlternatively, implement the menu functionality by using appropriate ARIA roles, states and properties. Working examples and information on implementing accessible ARIA menus can be found at https://www.w3.org/WAI/ARIA/apg/example-index/menubar/menubar-navigation.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (373, 'web', 'Custom checkboxes not operable with a keyboard', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are custom checkboxes that are not focusable or operable with a keyboard. Examples include:<br />\n- The &quot;SSSSS&quot; checkbox in the SSSSS section<br />\n- The &quot;SSSSS&quot; checkbox in the SSSSS section<br />\n- The &quot;SSSSS&quot; checkbox in the SSSSS section<br />\n<br />\nAs a result, keyboard users cannot select or deselect options, preventing interaction.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Replace the custom checkbox with the standard checkbox by using the &lt;input type=&quot;checkbox&quot;&gt; element.<br />\n<br />\nAlternatively, use appropriate ARIA roles and attributes to code the custom checkbox. Additionally, modify the scripts to ensure it&#039;s operable with the keyboard.<br />\n<br />\nA working example of custom checkbox can be found at:<br />\nhttps://www.w3.org/WAI/ARIA/apg/example-index/checkbox/checkbox.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (374, 'web', 'Custom drop-down not operable with a keyboard', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are custom drop-downs that are not focusable or operable with a keyboard. Examples include:<br />\n- The &quot;SSSSS&quot; drop-down present in the SSSSS section<br />\n- The &quot;SSSSS&quot; drop-down present in the SSSSS section<br />\n- The &quot;SSSSS&quot; drop-down present in the SSSSS section<br />\n<br />\nAs a result, users relying on keyboards are unable to select options from the drop-down.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Replace the custom dropdown with the standard dropdown using &lt;select&gt; and &lt;option&gt; elements.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (375, 'web', 'Custom radio buttons not operable with a keyboard', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are custom radio buttons that are not focusable or operable with a keyboard. Examples include:<br />\n- The &quot;SSSSS&quot; radio button group in the SSSSS section<br />\n- The &quot;SSSSS&quot; radio button group in the SSSSS section<br />\n- The &quot;SSSSS&quot; radio button group in the SSSSS section<br />\n<br />\nAs a result, keyboard users cannot make selections, blocking form submission.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Replace the custom radio button with the standard radio button by using the &lt;input type=&quot;radio&quot;&gt; element.<br />\n<br />\nAlternatively, use appropriate ARIA roles and attributes to code the custom radio buttons. Additionally, modify the scripts to ensure it&#039;s operable with the keyboard.<br />\n<br />\nA working example of custom radio button can be found at:<br />\nhttps://www.w3.org/WAI/ARIA/apg/example-index/radio/radio.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (376, 'web', 'Tabs not operable with a keyboard', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are tabs that are not operable with a keyboard. Examples include:<br />\n- The &quot;SSSSS&quot; tab interface in the SSSSS section does not allow switching between tabs using arrow keys.<br />\n<br />\nAs a result, keyboard-only users cannot access all tabbed content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Implement the tabs functionality by using appropriate WAI-ARIA roles, states and properties.<br />\nModify the scripts of the tabs to ensure that the tabs are accessible for all users.<br />\n<br />\nA working example of accessible tab functionality can be found at https://www.w3.org/WAI/ARIA/apg/example-index/tabs/tabs-manual.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (377, 'web', 'Tooltip content not accessible with a keyboard', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are tooltips that are not accessible with a keyboard. Examples include:<br />\n- The &quot;SSSSS&quot; tooltip in the SSSSS section only appears on mouse hover and is not available on keyboard focus.<br />\n<br />\nAs a result, users navigating via keyboard miss important contextual information.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Modify scripts to make the tooltip information available on hover as well as on focus. In addition along with mouse specific event handlers, use keyboard specific event handlers, such as &quot;onfocus&quot;, &quot;onblur&quot;and so on to make the functionality accessible for keyboard-only users.<br />\n• Specify the ARIA role &quot;tooltip&quot; for the information displayed on hover. Specify an unique &quot;id&quot; attribute for the tooltip and reference it via the &quot;aria-describedby&quot; attribute of the mentioned button.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (378, 'web', 'Date selector control not operable with a keyboard', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are date selector controls that are not operable with a keyboard. Examples include:<br />\n- The &quot;SSSSS&quot; date picker in the SSSSS section does not allow navigation or selection using keyboard keys.<br />\n<br />\nAs a result, users may be unable to enter dates without using a mouse.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Code the date selector control using &lt;button&gt; tag.<br />\n• Provide accessible names to the date selector control via inner text of the &lt;button&gt; tag.<br />\n• Ensure that the calendar for selecting the date is coded as dialog using appropriate ARIA roles, state and attributes.<br />\n<br />\nAlternatively, Apply the following changes:<br />\n• Provide date input field to allow a user to enter a date manually using the keyboard along with the date selector widget.<br />\n• To help screen reader users submit the form successfully, include the instruction about date format within the &lt;label&gt; tag of the date input field. <br />\n• If hidden instruction is provided, provide unique ID attribute for the instruction text and reference it to the &#039;aria-describedby&#039; attribute provide to the &lt;input&gt; tag.<br />\n<br />\nA working example of accessible date selector widget can be found at below links:<br />\n• https://www.w3.org/WAI/ARIA/apg/example-index/dialog-modal/datepicker-dialog<br />\n• https://www.w3.org/WAI/ARIA/apg/example-index/combobox/combobox-datepicker.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (379, 'web', 'Expand/collapse functionality not operable with a keyboard', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are expandable elements that cannot be expanded or collapsed and/or are not focusable using the keyboard alone. Examples include:<br />\n- The &quot;SSSSS&quot; button in the SSSSS section<br />\n- The &quot;SSSSS&quot; button in the SSSSS section<br />\n- The &quot;SSSSS&quot; button in the SSSSS section<br />\n<br />\nAs a result, keyboard users are blocked from accessing or hiding content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Code the mentioned interactive elements using &lt;button&gt; tag. <br />\n• Set the “aria-expanded” attribute to “false” for the button when the button is in the collapsed state.<br />\n• Ensure that the value of the “aria-expanded” attribute changes on user interaction via scripting.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment, Motor Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (380, 'web', 'Buttons not operable with a keyboard', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are elements that are not focusable or operable with the keyboard alone. Examples include:<br />\n- The &quot;SSSSS&quot; button in the SSSSS section<br />\n- The &quot;SSSSS&quot; button in the SSSSS section<br />\n- The &quot;SSSSS&quot; button in the SSSSS section<br />\n<br />\nAs a result, keyboard users are blocked from accessing the content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure all interactive element elements are focusable and operable with the keyboard alone. To resolve this, use native &lt;button&gt; element, since it has the keyboard operability by default.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment, Motor Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (381, 'web', 'Links not operable with a keyboard', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are links that are not focusable or operable with a keyboard. Examples include:<br />\n- The &quot;SSSSS&quot; link in the SSSSS section<br />\n- The &quot;SSSSS&quot; link in the SSSSS section<br />\n- The &quot;SSSSS&quot; link in the SSSSS section<br />\n<br />\nAs a result, users who rely on keyboard navigation cannot access linked content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Code the mentioned link using &lt;a&gt; tag and include the href attribute.<br />\n<br />\nA working example of accessible link can be found at<br />\nhttps://www.w3.org/WAI/ARIA/apg/patterns/link/</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment, Motor Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (382, 'web', 'Bookmark links do not work', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are bookmark links that do not work. Examples include:<br />\n- The &quot;SSSSS&quot; in-page link in the SSSSS section does not navigate to the correct anchor.<br />\n<br />\nAs a result, screen reader and keyboard users may not be able to jump to important sections.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Provide unique &quot;id&quot; aatribute to the target container.<br />\n• Ensure that the href attribute of &lt;a&gt; tag is properly referenced to target container.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment, Motor Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (383, 'web', 'Drag and drop functionality is inaccessible for keyboard-only and screen reader users', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is drag-and-drop functionality that is inaccessible for keyboard-only and screen reader users. Examples include:<br />\n- The &quot;SSSSS&quot; draggable item in the SSSSS section requires mouse-only interaction.<br />\n<br />\nAs a result, users who rely on keyboards or assistive technologies cannot perform drag-and-drop actions.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Code the dragable elements (answers) using native HTML &lt;button&gt; element. Alternatively, specify role=&quot;button&quot; for &lt;div&gt; element in which the answers are structured along with tabindex value of ‘0’ and required scripts for making it keyboard operable as well as mouse.<br />\n• Provide an off-screen text as &quot;selected&quot; as soon as any draggable element is selected to convey it&#039;s state. This should be handled via scripting when an element is selected or deselected.<br />\n<br />\nTo place the text off-screen:<br />\n.off-screen<br />\n{clip: rect(1px, 1px, 1px, 1px);<br />\nclip-path: inset(50%);<br />\nheight: 1px;<br />\nwidth: 1px;<br />\nmargin: -1px;<br />\noverflow: hidden;<br />\npadding: 0;<br />\nposition: absolute;}<br />\n<br />\n• As soon as any answer is selected, the focus should be shifted on the droppable area using JavaScript .focus(). For keyboard only users, the focus will be set to the first droppable area. The droppable &lt;div&gt; areas will also require tabindex=”0” value as soon as the draggable element is selected.<br />\n• Specify role=&quot;region&quot; to container which consists of droppable area. Also, provide a visual text to identify the droppable block. For example, &quot;Drop - Answer for Question 1 here&quot;.<br />\n• Provide keyboard mechanism as below for the functionality:<br />\n o An Escape key mechanism for users to cancel the entire functionality.<br />\n o An Enter key to drop an answer in the respective droppable area.<br />\n• Once, the draggable element is placed in the respective droppable areas, provide a visual feedback to the users. Make this alert available for the screen reader users by structuring the message within a &lt;div&gt; element and providing a role of alert to the div as soon as the message is displayed. Use ARIA live region properties to make the feedback available to screen reader users and set the politeness level to &quot;assertive&quot;.<br />\n• When the action is completed or aborted, clean-up the interface by loading the default values and making the droppable area non-interactive. Also, move the focus to the first draggable element using javascript .focus() method, where the user can start again.<br />\n• Provide visual instructions on how to access the functionality.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (384, 'web', 'Slider not keyboard operable', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are sliders that are not operable with a keyboard. Examples include:<br />\n- The &quot;SSSSS&quot; slider control in the SSSSS section does not respond to arrow keys or other keyboard input.<br />\n<br />\nAs a result, users are unable to change values using a keyboard.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Implement the sliders using native HTML `&lt;input type=&quot;range&quot;&gt;` element.<br />\n• Provide appropriate attributes such as min and max to define the minimum and maximum range of slider.<br />\n<br />\nFor more information visit https://developer.mozilla.org/en-US/docs/Web/HTML/Element/input/range<br />\n<br />\nAlternatively, implement the sliders using appropriate ARIA roles, states and properties<br />\n• Provide tabindex=”0” to make it focusable for keyboard-only and screen reader users.<br />\n• Modify the scripts to make the slider keyboard operable.<br />\n<br />\nFor more information visit https://www.w3.org/WAI/ARIA/apg/patterns/slider/</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment, Motor Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (385, 'web', 'Keyboard focus traps', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are keyboard focus traps that prevent users from navigating through the rest of the content. Examples include:<br />\n- After interacting with the &quot;SSSSS&quot; modal in the SSSSS section, the focus cannot be moved to elements outside the modal.<br />\n<br />\nAs a result, keyboard users may get stuck and cannot continue navigating the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the keyboard focus does not get trapped on any component and users can navigate the page content with ease in all the browsers. Modify the scripts associated with the dropdown list to ensure that keyboard trap can be avoided.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.2\",\"wcagsuccesscriterianame\":\"Keyboard Trap\",\"gigw30\":\"5.2.22\",\"is17802\":\"9.2.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (386, 'web', 'Missing instruction for character key shortcuts', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are missing instructions for character key shortcuts, impacting users who rely on screen readers or speech input devices. Examples include:<br />\n- The &quot;SSSSS&quot; shortcut functionality in the SSSSS section triggers actions without any documentation or tooltip.<br />\n<br />\nAs a result, users may activate shortcuts unknowingly or fail to discover them, affecting usability.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following chnages:<br />\n• For the benefit of speech input users, it is recommended to provide an option to disable or remap the character key shortcuts at the beginning of the page. <br />\n•  For the benefit of screen reader users, help section must be added that will include the details on how screen reader users can access the shortcuts.<br />\n<br />\nFor example, <br />\n• NVDA users can press &quot;NVDA Modifier Key + Space&quot; to turn on Focus Mode. In Focus Mode, users can press the shortcuts and access the functionality. <br />\n• JAWS users can press &quot;JAWS Modifier Key + Z&quot; to turn off Virtual PC cursor. Once the Virtual PC cursor is turned off then users can press the shortcuts to access the functionality.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment, Motor Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.4\",\"wcagsuccesscriterianame\":\"Character Key Shortcuts\",\"gigw30\":\"5.2.23\",\"is17802\":\"9.2.1.4\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (387, 'web', 'Character key shortcuts cannot be switched off or customized', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are character key shortcuts that cannot be switched off or customized, leading to accidental activation. Examples include:<br />\n- The &quot;SSSSS&quot; shortcut in the SSSSS section triggers action without option to disable or remap.<br />\n<br />\nAs a result, users may experience unintended actions, leading to confusion or disruption.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>If a keyboard shortcut is implemented in content using only letter (including upper- and lower-case letters), punctuation, number, or symbol characters, then at least one of the following is true:<br />\nTurn off:<br />\nA mechanism is available to turn the shortcut off;<br />\nRemap:<br />\nA mechanism is available to remap the shortcut to include one or more non-printable keyboard keys (e.g., Ctrl, Alt);<br />\nActive only on focus:<br />\nThe keyboard shortcut for a user interface component is only active when that component has focus.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment, Motor Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.4\",\"wcagsuccesscriterianame\":\"Character Key Shortcuts\",\"gigw30\":\"5.2.23\",\"is17802\":\"9.2.1.4\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (388, 'web', 'User’s session expires automatically', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>User sessions expire automatically, which can disrupt the user experience, especially for users who need more time. Examples include:<br />\n- Session timeout on the &quot;SSSSS&quot; page in the SSSSS section after a fixed period with no extension option.<br />\n<br />\nAs a result, users with cognitive or physical disabilities may lose their progress or be forced to restart tasks.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>We recommend that one of the following techniques be adopted:<br />\n1. Turn off time limit – provide a mechanism, e.g. a button, to allow the user to turn off the time limit before encountering it (place the mechanism at the top of the page).<br />\n2. Adjust time limit – provide the ability to adjust the set time limit. Allow the user to set the time limit to at least ten times the length of the default setting. <br />\n3. Extend time limit – allow the user to extend their session before the time expires. Warn the user before the time expires and allow the user to simply extend the time (for example, by activating a link or button). Allow the user to extend the time limit at least ten times.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability, Motor Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.2.1\",\"wcagsuccesscriterianame\":\"Timing Adjustable\",\"gigw30\":\"5.2.24\",\"is17802\":\"9.2.2.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (389, 'web', 'No means to control slideshow content', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is no means to control slideshow content, making it difficult for users who need to pause or stop it. Examples include:<br />\n- The slideshow in the SSSSS section auto-advances without pause, stop, or manual navigation controls.<br />\n<br />\nAs a result, users with cognitive or vestibular disorders may be distracted or disoriented.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide users with an option to control the slideshow through start, stop and pause buttons or links. Also inform screen reader users in the form of instruction about the presence of slideshow in advance to help them access the web page with ease.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.2.2\",\"wcagsuccesscriterianame\":\"Pause, Stop, Hide\",\"gigw30\":\"5.2.25\",\"is17802\":\"9.2.2.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (390, 'web', 'No means to control moving, blinking, or scrolling content', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is no means to control moving, blinking, or scrolling content, which can be distracting or disorienting for users. Examples include:<br />\n- The &quot;SSSSS&quot; marquee in the SSSSS section moves continuously without pause or stop controls.<br />\n<br />\nAs a result, users with attention or sensory processing issues may find this content difficult to use.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide users with an option to control the moving content through stop/pause and play buttons. Alternatively, ensure the movement stops automatically after five seconds.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.2.2\",\"wcagsuccesscriterianame\":\"Pause, Stop, Hide\",\"gigw30\":\"5.2.25\",\"is17802\":\"9.2.2.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (391, 'web', 'Flickering content used', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are images that are missing alternative text. Examples include:  <br />\n- The &quot;&quot;SSSSS&quot;&quot; image on the &quot;&quot;SSSSS&quot;&quot; page has no `alt` attribute or equivalent description.<br />\n<br />\nAs a result, screen reader users cannot understand the purpose or content of the image, making the page less accessible.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure web pages do not contain anything that flashes more than three times in any one second period, or the flash is below the general flash and red flash thresholds.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Neurological Disability\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.3.1\",\"wcagsuccesscriterianame\":\"Three Flashes or Below Threshold\",\"gigw30\":\"5.2.26\",\"is17802\":\"9.2.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (392, 'web', 'Missing Skip to content link', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is a missing &quot;Skip to main content&quot; link, making it difficult for sighted keyboard-only users to navigate directly to the main content. Examples include:<br />\n- No skip link found on the &quot;SSSSS&quot; page in the SSSSS section.<br />\n<br />\nAs a result, keyboard users must tab through all navigation before reaching main content, slowing navigation.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Even though headings are defined on the page and this is sufficient to meet this success criteria, however, in order to assist sighted keyboard-only users, it is recommended that a “Skip to main content” link be provided. This link can be always visible, or it can be positioned off-screen and be displayed when it receives keyboard focus.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.1\",\"wcagsuccesscriterianame\":\"Bypass Blocks\",\"gigw30\":\"5.2.27\",\"is17802\":\"9.2.4.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (393, 'web', 'Landmarks not defined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are missing landmarks, making it difficult for screen reader users to navigate the page efficiently. Examples include:<br />\n- No landmark roles like &lt;main&gt; or &lt;navigation&gt; found on the &quot;SSSSS&quot; page in the SSSSS section.<br />\n<br />\nAs a result, screen reader users cannot quickly jump to relevant sections.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Provide header, main and footer landmark regions for the respective sections of the page.<br />\n• Provide navigation landmark region with appropriate accessible label as well.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (394, 'web', 'Inaccurate page title', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are inaccurate page titles, making it difficult for users to understand the page’s content from the title alone. Examples include:<br />\n- The page title &quot;SSSSS&quot; on the &quot;SSSSS&quot; page does not reflect the actual content.<br />\n<br />\nAs a result, users may become confused or misled about page purpose.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide meaningful and unique title for the webpage within the &lt;title&gt; tag in the page source.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.2\",\"wcagsuccesscriterianame\":\"Page Titled\",\"gigw30\":\"5.2.28\",\"is17802\":\"9.2.4.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (395, 'web', 'Focus moves inappropriately', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is inappropriate focus movement, which can confuse users and disrupt their navigation. Examples include:<br />\n- Focus jumps unexpectedly to &quot;SSSSS&quot; element on the &quot;SSSSS&quot; page after interaction.<br />\n<br />\nAs a result, this interrupts user workflow and can cause disorientation.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure focus does not move to randomly on the page. When a element is triggered focus should moved to the updated content instead moving to the top of the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.3\",\"wcagsuccesscriterianame\":\"Focus Order\",\"gigw30\":\"5.2.29\",\"is17802\":\"9.2.4.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (396, 'web', 'Non-interactive elements receive keyboard focus', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are non-interactive elements receiving keyboard focus, making navigation more difficult for keyboard-only users. Examples include:<br />\n- The inactive &quot;SSSSS&quot; element on the &quot;SSSSS&quot; page receives keyboard focus.<br />\n<br />\nAs a result, users waste time tabbing through non-functional items.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Remove the &#039;tabindex&#039; attribute from the non-interactive elements in the page source.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment, Motor Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.3\",\"wcagsuccesscriterianame\":\"Focus Order\",\"gigw30\":\"5.2.29\",\"is17802\":\"9.2.4.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (397, 'web', 'Illogical tab order', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are issues with the tab order, which is not following a logical sequence. Examples include:<br />\n1. The &quot;SSSS&quot; element <br />\n2. The &quot;SSSS&quot; element<br />\n3. The &quot;SSSS&quot; element<br />\n<br />\nAs a result, keyboard users face confusion and inefficiency navigating the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Place the content of the webpage in a correct sequence in the source code as it appears visually. Move the content in the page source in the mentioned order to ensure that the content is available in correct order. CSS can be used to maintain the presentation of the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.3\",\"wcagsuccesscriterianame\":\"Focus Order\",\"gigw30\":\"5.2.29\",\"is17802\":\"9.2.4.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (398, 'web', 'Hidden content receives keyboard focus', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are hidden interactive elements receiving keyboard focus. Examples include:<br />\n- The hidden &quot;SSSSS&quot; button on the &quot;SSSSS&quot; page can be focused but not seen.<br />\n<br />\nAs a result, this causes confusion for users relying on keyboard navigation.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide tabindex=&quot;-1&quot; to the mentioned hidden interactive element to ensure that element does not recive keyboard focus.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.3\",\"wcagsuccesscriterianame\":\"Focus Order\",\"gigw30\":\"5.2.29\",\"is17802\":\"9.2.4.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (399, 'web', 'Keyboard focus not restricted in modal dialog', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are issues with keyboard focus not being restricted inside modal dialogs. Examples include:<br />\n- Focus moves outside the &quot;SSSSS&quot; modal dialog on the &quot;SSSSS&quot; page.<br />\n<br />\nAs a result, keyboard-only and screen reader users can get lost or interact with background content unexpectedly.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Use aria-modal=&quot;true&#039;, aria-hidden=”true” and tabindex=&quot;-1&quot; to hide the background content from screen readers and keyboard-only users. Ensure that &quot;aria-hidden&quot; and tabindex=&quot;-1&quot; attributes are removed from the page source when user closes the modal dialog.<br />\n• Modify the scripts to ensure that the Tab and Shift + Tab keystrokes wrap the keyboard focus inside the modal dialog in all browsers.<br />\n<br />\nFor information on creating accessible modal dialog refer https://www.w3.org/WAI/ARIA/apg/example-index/dialog-modal/dialog.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.3\",\"wcagsuccesscriterianame\":\"Focus Order\",\"gigw30\":\"5.2.29\",\"is17802\":\"9.2.4.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (400, 'web', 'Keyboard focus not set onto modal dialog', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are issues with keyboard focus not being set to the first logical element of the modal dialog. Examples include:<br />\n- Focus on the &quot;SSSSS&quot; modal on the &quot;SSSSS&quot; page lands on a close button instead of the main dialog content.<br />\n<br />\nAs a result, keyboard-only and screen reader users may miss critical information upon dialog opening.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Set the keyboard focus to the first logical element of the modal dialog in this case using the javascript .focus().<br />\n<br />\nFor information on creating accessible modal dialog refer https://www.w3.org/WAI/ARIA/apg/example-index/dialog-modal/dialog.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.3\",\"wcagsuccesscriterianame\":\"Focus Order\",\"gigw30\":\"5.2.29\",\"is17802\":\"9.2.4.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (401, 'web', 'Keyboard focus not set onto non-modal dialog', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are issues with keyboard focus not being set to the first logical element of non-modal dialogs. Examples include:<br />\n- Focus on the &quot;SSSSS&quot; non-modal dialog on the &quot;SSSSS&quot; page defaults incorrectly to the body element.<br />\n<br />\nAs a result, keyboard-only and screen reader users can get lost or interact with non-modal dialog unexpectedly.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Set the keyboard focus to the first logical element of the non-modal dialog in this case using the javascript .focus().</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.3\",\"wcagsuccesscriterianame\":\"Focus Order\",\"gigw30\":\"5.2.29\",\"is17802\":\"9.2.4.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (402, 'web', 'Keyboard focus does not return to the triggering element of non-modal dialog', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are issues with keyboard focus not returning to the triggering element of non-modal dialogs. Examples include:<br />\n- After closing the &quot;SSSSS&quot; dialog on the &quot;SSSSS&quot; page, focus does not return to the button that opened it.<br />\n<br />\nAs a result, keyboard-only and screen reader users lose context and must find their place manually.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Set the keyboard focus to the triggering element of the dialog using the JavaScript .focus().<br />\n<br />\nFor information on creating accessible modal dialog refer https://www.w3.org/WAI/ARIA/apg/example-index/dialog-modal/dialog.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.3\",\"wcagsuccesscriterianame\":\"Focus Order\",\"gigw30\":\"5.2.29\",\"is17802\":\"9.2.4.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (403, 'web', 'Keyboard focus does not return to the triggering element of modal dialog', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are issues with the keyboard focus not returning to the triggering element of modal dialogs. Examples include:<br />\n- After closing the &quot;SSSSS&quot; modal on the &quot;SSSSS&quot; page, focus is lost or moved elsewhere unexpectedly.<br />\n<br />\nAs a result, this breaks the flow for keyboard-only and screen reader users.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the keyboard focus moves the triggering element when the modal dialog is closed which can be achieved via JavaScript focus() method.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.3\",\"wcagsuccesscriterianame\":\"Focus Order\",\"gigw30\":\"5.2.29\",\"is17802\":\"9.2.4.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (404, 'web', 'Non-descriptive link text', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are link texts that are identical or non-descriptive. Examples include:<br />\n- Multiple links labeled &quot;Click here&quot; on the &quot;SSSSS&quot; page in the SSSSS section.<br />\n<br />\nAs a result, screen reader users cannot determine link purpose or destination easily.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Specify the &quot;id&quot; attribute with a unique value to the heading element of the corresponding link.<br />\n• Specify &quot;aria-labelledby&quot; attribute to the mentioned &lt;a&gt; element containing text.<br />\n• Reference both the &quot;id&quot; attribute values (of &lt;a&gt; and heading elements) via &quot;aria-labelledby&quot; attribute.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.4\",\"wcagsuccesscriterianame\":\"Link Purpose (In Context)\",\"gigw30\":\"5.2.30\",\"is17802\":\"9.2.4.4\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (405, 'web', 'Lengthy link text', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are lengthy link texts that can overwhelm users or cause confusion. Examples include:<br />\n- The link text &quot;SSSSS&quot; in the SSSSS section exceeds recommended length, making it difficult to scan.<br />\n<br />\nAs a result, this negatively impacts usability and cognitive load on screen reader users.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Remove the &lt;a&gt; element from the entire section.<br />\n• Mark-up the text that looks like heading using heading mark-up.<br />\n• Code only those text as a links which look like a link.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.4\",\"wcagsuccesscriterianame\":\"Link Purpose (In Context)\",\"gigw30\":\"5.2.30\",\"is17802\":\"9.2.4.4\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (406, 'web', 'Missing link text', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are links that do not have any link text. Examples include:<br />\n- The link with no visible or aria-label text on the &quot;SSSSS&quot; page.<br />\n<br />\nAs a result, screen reader users cannot identify the link’s purpose.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Specify unique and descriptive text for each link on the page. If there is no functionality associated with the link, specify tabindex=“-1” and “display:none” CSS property to ensure that the link is not available for keyboard-only and screen reader users.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.4.4\",\"wcagsuccesscriterianame\":\"Link Purpose (In Context)\",\"gigw30\":\"5.2.30\",\"is17802\":\"9.2.4.4\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (407, 'web', 'Multiple ways not defined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are issues with multiple ways not being defined to locate a webpage. Examples include:<br />\n- The &quot;SSSSS&quot; page lacks unique URLs, titles, or landmarks for navigation.<br />\n<br />\nAs a result, this reduces findability and accessibility.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure more than one way is available to locate a Web page within a set of Web pages except where the Web Page is the result of, or a step in, a process.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability, Visual Impairment,\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A A\",\"wcagsuccesscriteria\":\"2.4.5\",\"wcagsuccesscriterianame\":\"Multiple Ways\",\"gigw30\":\"5.2.31\",\"is17802\":\"9.2.4.5\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (408, 'web', 'Non-descriptive labels for buttons', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are button labels that are identical or non-descriptive. Examples include:<br />\n- Multiple buttons labeled &quot;Submit&quot; on the &quot;SSSSS&quot; page with no additional context.<br />\n<br />\nAs a result, screen reader users cannot distinguish between buttons’ purposes.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Specify appropriate label for the button using hidden text or &quot;aria-label&quot; attribute.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"2.4.6\",\"gigw30\":\"5.2.32\",\"is17802\":\"9.2.4.6\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (409, 'web', 'Inappropriate label for button', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are buttons that have inappropriate labels. Examples include:<br />\n- The button labeled &quot;Cancel&quot; that actually submits data on the &quot;SSSSS&quot; page.<br />\n<br />\nAs a result, this misleads screen reader users and may cause confustion understanding the purpose of the buttons.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Specify appropriate label for the button using hidden text or &quot;aria-label&quot; attribute.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"2.4.6\",\"wcagsuccesscriterianame\":\"Headings and Labels\",\"gigw30\":\"5.2.32\",\"is17802\":\"9.2.4.6\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (410, 'web', 'Focus not visible', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are interactive elements where the focus is not visible. Examples include:<br />\n- The &quot;SSSSS&quot; input field on the &quot;SSSSS&quot; page does not show a focus ring or highlight.<br />\n<br />\nAs a result, keyboard users cannot track their location.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Set the CSS outline property for the mentioned button to ensure that clear focus indication is available for users.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"2.4.7\",\"wcagsuccesscriterianame\":\"Focus Visible\",\"gigw30\":\"5.2.33\",\"is17802\":\"9.2.4.7\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (411, 'web', 'Use of pointer gestures without alternative way', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are functionalities that require multipoint or path-based gestures without an alternative. Examples include:<br />\n- The &quot;SSSSS&quot; zoom feature on the &quot;SSSSS&quot; page requires pinch-to-zoom on touch devices only.<br />\n<br />\nAs a result, mobility impaired users unable to perform these gestures are excluded.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure all functionality that uses multipoint or path-based gestures for operation can be operated with a single pointer without a path-based gesture, unless a multipoint or path-based gesture is essential.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment, Motor Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.5.1\",\"wcagsuccesscriterianame\":\"Pointer Gestures\",\"gigw30\":\"5.2.34\",\"is17802\":\"9.2.5.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (412, 'web', 'Functionality gets activated on down event', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are functions that get activated on the down event. Examples include:<br />\n- The &quot;SSSSS&quot; button on the &quot;SSSSS&quot; page triggers action on mousedown instead of click.<br />\n<br />\nAs a result, this can cause accidental activations or inconsistent behavior for mobility impaired users.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that for functions operable with a single pointer, at least one of the following conditions is met: the down-event does not trigger any part of the function; the function completes on the up-event, with a mechanism available to abort it before completion or to undo it afterward; the up-event reverses the effects of the preceding down-event; or completing the function on the down-event is essential.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment, Motor Impairment, Cognitive Disability\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.5.2\",\"wcagsuccesscriterianame\":\"Pointer Cancellation\",\"gigw30\":\"5.2.35\",\"is17802\":\"9.2.5.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (413, 'web', 'Accessible name does not match with visual label', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are elements where the accessible name does not match the visual label. Examples include:<br />\n- The &quot;SSSSS&quot; form input label says &quot;Email&quot; visually but has accessible name &quot;Phone Number.&quot;<br />\n<br />\nAs a result, this confuses assistive technology users.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the visible text of the element is included within its accessible name.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Speech-input Users\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.5.3\",\"wcagsuccesscriterianame\":\"Label in Name\",\"gigw30\":\"5.2.36\",\"is17802\":\"9.2.5.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (414, 'web', 'No alternatives for motion activation', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are functionalities that rely on motion activation without alternatives. Examples include:<br />\n- The &quot;SSSSS&quot; feature on the &quot;SSSSS&quot; page activates when device motion is detected.<br />\n<br />\nAs a result, users without motion-enabled devices or who cannot perform motion are excluded.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Developers should ensure that functionality operable by device or user motion can also be managed through user interface components, allowing for the disabling of motion responses to prevent accidental activation. However, this should not apply in cases where the motion is used to operate functionality via an accessibility-supported interface, or when the motion is essential for the function, as disabling it would compromise the activity.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.5.4\",\"wcagsuccesscriterianame\":\"Motion Actuation\",\"gigw30\":\"5.2.37\",\"is17802\":\"9.2.5.4\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (415, 'web', 'Language not defined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>The page does not have the &#039;lang&#039; attribute on the &lt;html&gt; element with proper value.<br />\n<br />\nAs a result, this makes it difficult for screen readers to select correct language and pronunciation.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Specify an appropriate &#039;lang&#039; attribute in the &lt;html&gt; element as per the primary language of the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"3.1.1\",\"gigw30\":\"5.2.38\",\"is17802\":\"9.3.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (416, 'web', 'Language defined incorrectly', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>The &#039;lang&#039; attribute on the &lt;html&gt; element is defined with an inappropriate value of &quot;SSSSSS&quot;.<br />\n<br />\nAs a result, users relying on screen readers may hear incorrect or no language indication, causing confusion.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Specify an appropriate &#039;lang&#039; attribute in the &lt;html&gt; element as per the primary language of the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"3.1.1\",\"gigw30\":\"5.2.38\",\"is17802\":\"9.3.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (417, 'web', 'Change of language not identified for text', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are changes in language that are not identified for text. Examples include:<br />\n- Sections of text on the &quot;SSSSS&quot; page lack language change markup.<br />\n<br />\nAs a result, screen reader users may receive incorrect pronunciation, affecting comprehension.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Specify an appropriate &#039;lang&#039; attribute for the respective &lt;span&gt; tag of mentioned text that is in a different language to the rest of the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"3.1.2\",\"gigw30\":\"5.2.39\",\"is17802\":\"9.3.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (418, 'web', 'Change of language identified incorrectly for the text', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are instances where the language change is identified incorrectly for the text. Examples include:<br />\n- The language of a paragraph on the &quot;SSSSS&quot; page is marked as English when it is in Spanish.<br />\n<br />\nAs a result, screen reader users may be confused by incorrect pronunciation or intonation.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Specify an appropriate &#039;lang&#039; attribute for the respective &lt;span&gt; tag of mentioned text that is in a different language to the rest of the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"3.1.2\",\"gigw30\":\"5.2.39\",\"is17802\":\"9.3.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (419, 'web', 'Unexpected change of context on focus', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are elements where focus causes an unexpected change of context. Examples include:<br />\n- Focusing on the &quot;SSSSS&quot; button on the &quot;SSSSS&quot; page unexpectedly shifts content without warning.<br />\n<br />\nAs a result, keyboard and screen reader users may become disoriented or lose track of where they are.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure when any component receives focus, it does not initiate a change of context.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"3.2.1\",\"gigw30\":\"5.2.40\",\"is17802\":\"9.3.2.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (420, 'web', 'Form controls update content on input', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are form controls that update content on input without prior warning. Examples include:<br />\n- Entering text in the &quot;SSSSS&quot; field on the &quot;SSSSS&quot; page dynamically updates other content without alert.<br />\n<br />\nAs a result, screen reader users may miss important changes, causing confusion or errors during form completion.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure changing the setting of any user form control not automatically cause a change of context unless the user has been advised of the behavior before using the component.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"3.2.2\",\"gigw30\":\"5.2.41\",\"is17802\":\"9.3.2.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (421, 'web', 'Navigation is not consistent', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are navigation mechanisms that are not consistent. Examples include:<br />\n- Navigation menus on the &quot;SSSSS&quot; page behave differently across sections.<br />\n<br />\nAs a result, screen reader and cognitive impaired users may find it difficult to predict navigation behavior, causing frustration.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure navigational mechanisms that are repeated on multiple Web pages within a set of Web pages occur in the same relative order each time they are repeated, unless a change is initiated by the user.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"3.2.3\",\"gigw30\":\"5.2.42\",\"is17802\":\"9.3.2.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (422, 'web', 'Elements naming not consistent', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are elements whose naming is not consistent. Examples include:<br />\n- The &quot;SSSSS&quot; button is labeled differently in various parts of the &quot;SSSSS&quot; page.<br />\n<br />\nAs a result, users relying on assistive technology may be confused by inconsistent labels.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure components that have the same functionality within a set of Web pages are identified consistently.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Coginitve Disability, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"3.2.4\",\"wcagsuccesscriterianame\":\"Consistent Identification\",\"gigw30\":\"5.2.43\",\"is17802\":\"9.3.2.4\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (423, 'web', 'Error messages difficult to locate', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are error messages that are difficult to locate. Examples include:<br />\n- Error message on the &quot;SSSSS&quot; form appears far from the relevant field.<br />\n<br />\nAs a result, screen reader users may not find or associate the error message with the input needing correction.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Add &#039;aria-describedby&#039; attribute to the form field.<br />\n• Reference &#039;id&#039; attribute value of the containner used to display the error message to &#039;aria-describedby&#039; attribute. <br />\n• Set focus on the first field with error using the JavaScript .focus() method as soon as the form is submitted.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability, Visual Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"3.3.1\",\"wcagsuccesscriterianame\":\"Error Identification\",\"gigw30\":\"5.2.44\",\"is17802\":\"9.3.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (424, 'web', 'Generic error message', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are generic error messages. Examples include:<br />\n- The &quot;SSSSS&quot; form shows &quot;Invalid input&quot; without details.<br />\n<br />\nAs a result, cognitive impaired users may be unsure how to correct the issue, delaying task completion.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that descriptive and specific error messages are provided for fields with error, for e.g. “First name field is required&quot;.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"3.3.3\",\"wcagsuccesscriterianame\":\"Error Suggestion\",\"gigw30\":\"5.2.46\",\"is17802\":\"9.3.3.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (425, 'web', 'Missing Error messages', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are missing error messages when a form is submitted with errors. Examples include:<br />\n- No error is shown when submitting the &quot;SSSSS&quot; form with invalid data.<br />\n<br />\nAs a result, users may think the form was submitted successfully and become confused.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>When the form is submitted with errors along with color, display a list of error messages at the beginning of the form. Error messages must clearly describe the problem that has occurred and include suggestions (wherever possible) on how to rectify it.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability, Visual Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"3.3.1\",\"wcagsuccesscriterianame\":\"Error Identification\",\"gigw30\":\"5.2.44\",\"is17802\":\"9.3.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (426, 'web', 'Mandatory fields not identified', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are mandatory fields that are not identified. Examples include:<br />\n- Required fields on the &quot;SSSSS&quot; form lack visual or programmatic indication.<br />\n<br />\nAs a result, users, especially those relying on screen readers, may miss required inputs, leading to form submission errors.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Provide the asterisk (*) within the label mark-up of the mandatory form fields.<br />\nAdditionally, provide an instruction &quot;* denotes mandatory fields&quot; at the beginning of the form to ensure all users can access the instruction.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"3.3.2\",\"gigw30\":\"5.2.45\",\"is17802\":\"9.3.3.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (427, 'web', 'Missing visual instruction for mandatory fields', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are missing visual instructions for mandatory fields. Examples include:<br />\n- The &quot;SSSSS&quot; field on the &quot;SSSSS&quot; page lacks instruction that it is required.<br />\n<br />\nAs a result, sighted users and users with cognitive disabilities may not realize the need to fill these fields.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure  to provide an instruction &quot;* denotes mandatory fields&quot; at the beginning of the form to ensure all users can access the instruction.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"3.3.2\",\"wcagsuccesscriterianame\":\"Labels or Instructions\",\"gigw30\":\"5.2.45\",\"is17802\":\"9.3.3.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (428, 'web', 'Missing visual label for form fields', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are missing visual labels for form fields. Examples include:<br />\n- The &quot;SSSSS&quot; input on the &quot;SSSSS&quot; page lacks a visible label.<br />\n<br />\nAs a result, users, including those with cognitive impairments or low vision, may have difficulty understanding the purpose of the field.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Provide unique and descriptive label for mentioned form fields using &lt;label&gt; element.<br />\n• Associate the label explicitly with the form field by providing identical value which is unique from other IDs to &quot;for&quot; and &quot;id&quot; attributes of the label and form field respectively.<br />\n<br />\nAlternatively, use either hidden labels or &quot;title&quot; or &quot;aria-label&quot; attribute to convey the purpose of the form fields to screen reader users as well as maintain the presentation.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability, Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"3.3.2\",\"gigw30\":\"5.2.45\",\"is17802\":\"9.3.3.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (429, 'web', 'Incorrect placement of instruction', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is incorrect placement of instruction. Examples include:<br />\n- Instructions for the &quot;SSSSS&quot; field appear far from the input on the &quot;SSSSS&quot; page.<br />\n<br />\nAs a result, users with cognitive disabilities or low vision may miss the instructions and make errors.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Place the instruction at the beginning of the form to ensure all users can access it.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability, Visual Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"3.3.2\",\"gigw30\":\"5.2.45\",\"is17802\":\"9.3.3.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (430, 'web', 'Missing suggestions to resolve errors', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are missing suggestions to resolve errors. Examples include:<br />\n- The error message on the &quot;SSSSS&quot; form does not suggest how to fix the input.<br />\n<br />\nAs a result, users with cognitive disabilities may struggle to correct their input.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure if an input error is automatically detected and suggestions for correction are known, then the suggestions are provided to the user, unless it would jeopardize the security or purpose of the content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"3.3.3\",\"gigw30\":\"5.2.46\",\"is17802\":\"9.3.3.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (431, 'web', 'Form submitted with errors', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are forms that can be submitted with errors. Examples include:<br />\n- The &quot;SSSSS&quot; form submits despite invalid or incomplete fields.<br />\n<br />\nAs a result, all users, including those with cognitive disabilities, may submit faulty data, causing downstream issues.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that web pages involving legal commitments, financial transactions, modification or deletion of user-controlled data, or submission of user test responses meet at least one of the following criteria to prevent errors: submissions should be reversible; data entered by the user must be checked for input errors, allowing for corrections; or there should be a mechanism for reviewing, confirming, and correcting information before finalizing the submission.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"3.3.4\",\"wcagsuccesscriterianame\":\"Error Prevention (Legal, Financial, Data)\",\"gigw30\":\"5.2.47\",\"is17802\":\"9.3.34\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (432, 'web', 'Multiple parsing errors', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are multiple parsing errors. Examples include:<br />\n- The &quot;SSSSS&quot; page HTML contains unclosed tags causing screen reader issues.<br />\n<br />\nAs a result, screen reader users may experience skipped or misread content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>To meet accessibility conformance, it is necessary that the following requirements are met:<br />\n• All elements are nested properly according to their HTML specifications.<br />\n• All elements have complete start `&lt;&gt;` and end `&lt;/&gt;` tags.<br />\n• Within each page, the elements use unique `id` attribute values.<br />\n• Elements do not have duplicate attributes.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.1\",\"gigw30\":\"5.2.48\",\"is17802\":\"9.4.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (433, 'web', 'Missing role for custom controls', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are custom controls that do not have appropriate role information. Examples include:<br />\n- The &quot;SSSSS&quot; custom slider on the &quot;SSSSS&quot; page lacks role=&#039;slider&#039;.<br />\n<br />\nAs a result, assistive technology users, including screen reader users, cannot identify control types, leading to confusion.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that your web application implements proper roles for interactive elements. Consider the following roles and their corresponding HTML elements:<br />\n<br />\n• Button: Use the &lt;button&gt; element or set role=&quot;button&quot; on non-button elements.<br />\n• Link: Utilize the &lt;a href=&quot;#&quot;&gt; tag for navigational links.<br />\nText Input: Use &lt;input type=&quot;text&quot;&gt; for text fields.<br />\n• Checkbox: Use &lt;input type=&quot;checkbox&quot;&gt; for checkbox controls.<br />\n• Radio Button: Use &lt;input type=&quot;radio&quot;&gt; for radio button options.<br />\n• Dropdown Menu: Use the &lt;select&gt; element for dropdowns.<br />\n• Menu: Set role=&quot;menu&quot; for the container and role=&quot;menuitem&quot; for individual items.<br />\n• Dialog Box: Use role=&quot;dialog&quot; to indicate interactive content.<br />\n• Alert: Use role=&quot;alert&quot; for important notifications that require user attention.<br />\n• Progress Indicator: Use role=&quot;progressbar&quot; for indicating progress in tasks.<br />\n• Slider: Use role=&quot;slider&quot; for interactive sliders.<br />\n• Tab List: Use role=&quot;tablist&quot; for grouping tabs, and role=&quot;tab&quot; for individual tabs.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (434, 'web', 'Missing state for custom controls', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are custom controls that do not have appropriate state information. Examples include:<br />\n- The &quot;SSSSS&quot; toggle button does not reflect its checked state.<br />\n<br />\nAs a result, users of assistive technologies may not determine control status.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that your web application appropriately conveys states for interactive elements. Consider the following roles and their corresponding HTML attributes:<br />\n<br />\n• Button State: Use aria-pressed=&quot;true&quot; or aria-pressed=&quot;false&quot; for toggle buttons to indicate their pressed state.<br />\n• Checkbox State: Use aria-checked=&quot;true&quot; or aria-checked=&quot;false&quot; to convey whether a checkbox is checked or unchecked.<br />\n• Radio Button State: Use aria-checked=&quot;true&quot; or aria-checked=&quot;false&quot; to indicate the selection state of radio buttons.<br />\n• Expanded/Collapsed State: Use aria-expanded=&quot;true&quot; or aria-expanded=&quot;false&quot; to indicate whether an expandable element is open or closed.<br />\n• Disabled State: Use aria-disabled=&quot;true&quot; to indicate that an element is not interactive.<br />\n• Current Step in a Wizard: Use aria-current=&quot;step&quot; on the current step element to clearly indicate which step the user is on.<br />\n• Step Indicators: For a list of steps, use aria-selected=&quot;true&quot; for the current step and aria-selected=&quot;false&quot; for all other steps.<br />\n• Current page: Use aria-current=&quot;page&quot; on the current page link (&lt;a&gt; element) to clearly indicate which page is currently opened.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (435, 'web', 'Missing name for custom controls', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are custom controls that do not have appropriate name information. Examples include:<br />\n- The &quot;SSSSS&quot; dropdown has no accessible name.<br />\n<br />\nAs a result, screen reader users may not understand the control purpose.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that your web application appropriately conveys name for interactive elements. This can be done by using aria-label or aria-labelledby attribute.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (436, 'web', 'Custom checkboxes not programmatically determined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are custom checkboxes that do not have appropriate role, name, and/or state information. Examples include:<br />\n- The custom checkbox on the &quot;SSSSS&quot; form lacks role and state info.<br />\n<br />\nAs a result, screen reader users cannot operate or understand the checkbox.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Replace the custom checkbox with the standard checkbox by using the &lt;input type=&quot;checkbox&quot;&gt; element.<br />\n<br />\nAlternatively, use appropriate ARIA roles and attributes to code the custom checkbox. Additionally, modify the scripts to ensure it&#039;s operable with the keyboard.<br />\n<br />\nA working example of custom checkbox can be found at:<br />\nhttps://www.w3.org/WAI/ARIA/apg/example-index/checkbox/checkbox.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (437, 'web', 'Custom radio buttons not programmatically determined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are custom radio buttons that do not have appropriate role, name, and/or state information. Examples include:<br />\n- The radio button group on the &quot;SSSSS&quot; page lacks ARIA roles.<br />\n<br />\nAs a result, users of assistive technologies may be unable to select or identify options.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Replace the custom radio button with the standard radio button by using the &lt;input type=&quot;radio&quot;&gt; element.<br />\n<br />\nAlternatively, use appropriate ARIA roles and attributes to code the custom radio buttons. Additionally, modify the scripts to ensure it&#039;s operable with the keyboard.<br />\n<br />\nA working example of custom radio button can be found at:<br />\nhttps://www.w3.org/WAI/ARIA/apg/example-index/radio/radio.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (438, 'web', 'Inappropriate use of ARIA attributes', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are elements that make use of ARIA attributes inappropriately. Examples include:<br />\n- The &quot;SSSSS&quot; button has conflicting ARIA roles on the &quot;SSSSS&quot; page.<br />\n<br />\nAs a result, screen reader users may receive incorrect or confusing information.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that ARIA attributes are used appropriately by relying on native HTML elements whenever possible, avoiding redundant roles on semantic elements. To resolve this, remove unnecessary ARIA attributes used on the mentioned elements.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (439, 'web', 'Tab not programmatically determined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are tabs that do not have appropriate role, name, and/or state information. Examples include:<br />\n- The tab list on the &quot;SSSSS&quot; page lacks proper ARIA markup.<br />\n<br />\nAs a result, screen reader users cannot navigate tabs correctly.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Implement the tabs functionality by using appropriate WAI-ARIA roles, states and properties.<br />\nModify the scripts of the tabs to ensure that the tabs are accessible for all users.<br />\n<br />\nA working example of accessible tab functionality can be found at https://www.w3.org/WAI/ARIA/apg/example-index/tabs/tabs-manual.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (440, 'web', 'Carousel not programmatically determined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>On activating the carousel controls under the &quot;SSSSSS&quot; section, the content of the respective slide gets dynamically updated. Although the dynamic change in the content is easier to understand for sighted users, it is not intuitive for screen reader users. Moreover, the region consisting of carousel is not programmatically determined. <br />\n<br />\nAs a result, screen reader users cannot interact with the carousel content effectively.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Add role &quot;region&quot; and aria-label=&quot;Carousel&quot; attribute to the &lt;div&gt; element containing the carousel content.<br />\n• Add role=&quot;status&quot;to the  &lt;div&gt; tag containing the carousel content to ensure that the screen reader announces the updated content.<br />\n<br />\nFor more information on carousel, visit https://www.w3.org/WAI/ARIA/apg/example-index/carousel/carousel-1-prev-next</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (441, 'web', 'Missing iframe title', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are &lt;iframe&gt; elements that do not have an appropriate accessible name. Examples include:<br />\n- The &quot;SSSSS&quot; iframe on the &quot;SSSSS&quot; page has no accessible title.<br />\n<br />\nAs a result, screen reader users cannot understand the iframe content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Add appropriate &#039;title&#039; for all the frames and iframes used on the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (442, 'web', 'Inappropriate iframe title', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are &lt;iframe&gt; elements with inappropriate accessible names. Examples include:<br />\n- The &quot;SSSSS&quot; iframe is titled misleadingly on the &quot;SSSSS&quot; page.<br />\n<br />\nAs a result, screen reader users receive confusing or incorrect information.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Add appropriate &#039;title&#039; for all the frames and iframes used on the page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (443, 'web', 'Menu not programmatically determined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are menus that do not have appropriate role, name, and/or state information. Examples include:<br />\n- The dropdown menu on the &quot;SSSSS&quot; page lacks ARIA roles.<br />\n<br />\nAs a result, screen reader and keyboard-only users cannot navigate or understand menu options.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Implement the menu functionality by using appropriate ARIA roles, states and properties. Working examples and information on implementing accessible ARIA menus can be found at https://www.w3.org/WAI/ARIA/apg/example-index/menubar/menubar-navigation.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (444, 'web', 'Modal dialog is not programmatically identified', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are modal dialogs that do not have appropriate role and/or name information. Examples include:<br />\n- The &quot;SSSSS&quot; modal lacks role=&#039;dialog&#039; and accessible name.<br />\n<br />\nAs a result, screen reader users cannot identify the dialog properly.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Add role=&quot;dialog&quot;, aria-modal=&quot;true&quot; and &#039;aria-labelledby&#039; attribute to the &lt;div&gt; tag containing the modal dialog content.<br />\n• Specify &#039;id&#039; attribute with unique value to the &lt;div&gt; tag containing the heading and reference it via &#039;aria-labelledby&#039; attribute.<br />\n<br />\nFor information on creating accessible modal dialog refer https://www.w3.org/WAI/ARIA/apg/example-index/dialog-modal/dialog.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (445, 'web', 'Accordion not programmatically determined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are accordions that do not have appropriate role, name, and/or state information. Examples include:<br />\n- The FAQ accordion on the &quot;SSSSS&quot; page lacks ARIA markup.<br />\n<br />\nAs a result, screen reader users and keyboard-only users may not be able to expand or collapse content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Code the mentioned elements with native HTML &lt;button&gt; tag.<br />\n• Initially set the &#039;aria-expanded&#039; attribute to &#039;false&#039; for the button. Ensure that the value of the &#039;aria-expanded&#039; attribute changes on user interaction via scripting to &#039;false&#039; in collapsed state and &#039;true&#039; in expanded state.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (446, 'web', 'Slider not programmatically determined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>The &quot;SSSSS&quot; slider is not programmatically idenfied by screen reader users.<br />\n<br />\nThis made it difficult for keyboard and screen reader users to access the functionality associated with it.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Implement the sliders using native HTML &lt;input type=&quot;range&quot;&gt; element.<br />\n• Provide appropriate attributes such as min and max to define the minimum and maximum range of slider.<br />\n<br />\nFor more information visit https://developer.mozilla.org/en-US/docs/Web/HTML/Element/input/range<br />\n<br />\nAlternatively, implement the sliders using appropriate ARIA roles, states and properties<br />\n• Provide tabindex=”0” to make it focusable for keyboard-only and screen reader users.<br />\n• Modify the scripts to make the slider keyboard operable.<br />\n<br />\nFor more information visit https://www.w3.org/WAI/ARIA/apg/patterns/slider/</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (447, 'web', 'Role link not defined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are links that do not have appropriate role information. Examples include:<br />\n- The SSSSS link on the SSSSS page lacks role=link.<br />\n<br />\nAs a result, screen reader users may not recognize the element as a link.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the interactive navigation elements are programmatically identified as links.<br />\nApply the following changes:<br />\nNative implementation:<br />\n• Code the mentioned interactive elements using the native &lt;a href=&quot;...&quot;&gt; element. Ensure that &quot;href&quot; attribute is used with an appropriate value.<br />\n<br />\nARIA Implementation:<br />\n• Provide role=&quot;link&quot; for the &lt;div&gt; element of the mentioned navigation elements.<br />\n• Modify the scripts to ensure the mentioned interactive elements are keyboard operable.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (448, 'web', 'Non-modal dialog is not programmatically identified', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are non-modal dialogs that do not have an appropriate role and/or name information. Examples include:<br />\n- The tooltip on the SSSSS page lacks role and name.<br />\n<br />\nAs a result, keyboard-only and screen reader users cannot access the tooltip content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Add role=&quot;dialog&quot;, aria-modal=&quot;false&quot; and &quot;aria-labelledby&quot; attribute to the &lt;div&gt; tag containing the dialog content.<br />\n• Specify &#039;id&#039; attribute with unique value to the &lt;div&gt; tag containing the heading and reference it via &#039;aria-labelledby&#039; attribute.<br />\n<br />\nFor information on creating accessible modal dialog refer https://www.w3.org/WAI/ARIA/apg/example-index/dialog-modal/dialog.html</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (449, 'web', 'Expand/collapse state of the button not defined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are expandable buttons that do not have appropriate state information. Examples include:<br />\n- The expand/collapse button on the SSSSS page does not update aria-expanded.<br />\n<br />\nAs a result, screen reader users cannot know whether content is expanded.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Set &#039;aria-expanded&#039; attribute to &#039;false&#039; for the button by default as the button is in the collapsed state. Ensure that the value of &#039;aria-expanded&#039; attribute changes to &#039;true&#039; in expanded state on user interaction via scripting.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (450, 'web', 'Disabled state of the button not defined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are disabled controls that do not have the disabled state determined programmatically. Examples include:<br />\n- The SSSSS button is visually disabled but accessible.<br />\n<br />\nAs a result, keyboard-only and assistive technology users may try to interact with controls that are not usable.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Add aria-disabled=&quot;true&quot; attribute when the link is in the disabled state. Ensure that the value of &quot;aria-disabled&quot; attribute is updated to &quot;false&quot; when the link is in the enabled state on user interaction via scripting.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (451, 'web', 'Role button not defined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are buttons that do not have appropriate role information. Examples include:<br />\n- The SSSSS clickable element lacks role=button.<br />\n<br />\nAs a result, screen reader users and keyboard-only users may not recognize the element as a button.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the interactive elements are programmatically identified as buttons.<br />\nApply the following changes:<br />\nNative implementation:<br />\n• Code the mentioned interactive elements using the native &lt;button&gt; element.<br />\n<br />\nARIA Implementation:<br />\n• Provide role=&quot;button&quot; for the &lt;div&gt; element of the mentioned interactive elements.<br />\n• Modify the scripts to ensure the mentioned interactive elements are keyboard operable.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (452, 'web', 'Missing accessible name for slider control', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are slider controls that do not have appropriate role information. Examples include:<br />\n- The brightness slider on the SSSSS page lacks ARIA roles.<br />\n<br />\nAs a result, assistive technology users, including screen reader users, cannot interact properly.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Use hidden label or &quot;aria-label&quot; attribute to convey the purpose of the slider control.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (453, 'web', 'Unclear expand/collapse functionality of link', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are expandable links that do not have expand/collapse state information. Examples include:<br />\n- The expandable section link on the SSSSS page lacks aria-expanded.<br />\n<br />\nAs a result, screen reader users cannot know the expanded/collapsed state.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Set &#039;aria-expanded&#039; attribute to &#039;false&#039; for the link when the link is in the collapsed state. Ensure that the value of &#039;aria-expanded&#039; attribute changes to &#039;true&#039; in expanded state on user interaction via scripting.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (454, 'web', 'Expand/collapse state defined incorrectly', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are controls that are defined with incorrect expand/collapse state information. Examples include:<br />\n- The toggle button on the SSSSS page shows incorrect aria-expanded value.<br />\n<br />\nAs a result, screen reader users get incorrect feedback about content state.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Set the &quot;aria-expanded&quot; attribute to &quot;false&quot; when the buttons are collapsed. Ensure that the value of the &quot;aria-expanded&quot; attribute changes to &quot;true&quot; when buttons expand on user interaction via scripting.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (455, 'web', 'Content not available for screen reader users', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are contents that are not available for screen readers. Examples include:<br />\n- Important text on the SSSSS page is hidden from assistive technologies.<br />\n<br />\nAs a result, screen reader users miss vital information.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>It is recommended to specify the information as plain text and use styles for formatting effects.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (456, 'web', 'Current state is not defined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are links that do not have the current page state information. Examples include:<br />\n- The navigation link for the current page on the SSSSS page lacks aria-current.<br />\n<br />\nAs a result, screen reader users cannot determine which page is active.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the current state of the active link is defined using the &quot;aria-current&quot; attribute with an appropriate token value.<br />\nApply the following changes:<br />\n• Add the aria-current=&quot;page&quot; attribute to &lt;a&gt; element of the link.<br />\n• Ensure that the &quot;aria-current&quot; attribute is updated as per user interaction using scripting.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (457, 'web', 'Sort state not conveyed to screen reader users', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are sortable table headers that do not have state information. Examples include:<br />\n- The SSSSS column header lacks aria-sort on the SSSSS page.<br />\n<br />\nAs a result, screen reader users cannot determine sort order.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Add aria-sort=&quot;ascending&quot; attribute for &lt;th&gt; element for current table header for which user is perfroming sorting. Ensure that the value of aria-sort changes as per user intearction.<br />\n<br />\nA working example of Sortable tables can be found at<br />\nhttps://www.w3.org/WAI/ARIA/apg/example-index/table/sortable-table</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"4.1.2\",\"gigw30\":\"5.2.49\",\"is17802\":\"9.4.1.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (458, 'web', 'Dynamically updating content not announced for screen reader users', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are dynamically changing contents that are not announced to screen readers. Examples include:<br />\n- Live update sections on the SSSSS page do not notify screen readers.<br />\n<br />\nAs a result, screen reader users miss important real-time changes.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Use appropriate ARIA live region attribute or role to achieve this. Specify aria-live=&quot;polite&quot; or role=“status” to the container consisting remaining characters.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"4.1.3\",\"gigw30\":\"5.2.50\",\"is17802\":\"9.4.1.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (459, 'web', 'Search results not programmatically identified', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are search results that are not announced to screen readers. Examples include:<br />\n- Search results on the SSSSS page appear without announcement.<br />\n<br />\nAs a result, screen reader users may think no results are present.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Inform the user through hidden text in the label that entering text into the form field will trigger a list of options.<br />\n• Provide the number of suggestions found information through hidden text in the &lt;span&gt; tag after the input field when user enters text in the input field.<br />\no Specify role=&quot;status&quot; on the &lt;span&gt; tag.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"4.1.3\",\"gigw30\":\"5.2.50\",\"is17802\":\"9.4.1.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (460, 'web', 'Loading message not announced for screen reader users', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are loading messages that are not announced to screen readers. Examples include:<br />\n- Loading spinner on the SSSSS page is not announced.<br />\n<br />\nAs a result, screen reader users may think the page is unresponsive.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Specify ARIA role &quot;status&quot; for the container in which the loading message is present.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"4.1.3\",\"gigw30\":\"5.2.50\",\"is17802\":\"9.4.1.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (461, 'web', 'Status message not defined programmetically', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are status messages that are not programmatically determined. Examples include:<br />\n- Success messages on the SSSSS page lack ARIA live regions.<br />\n<br />\nAs a result, screen reader users may miss confirmation or alert messages.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Use ARIA live region to make sure that the dynamic update is announced for screen reader users. This can be achieved by either adding a live region role=&quot;status&quot; or  aria-live=&quot;polite&quot; and aria-atomic=&quot;true&quot; attributes to the container used to display the message. Make sure the live region is present in the page source by default.<br />\n<br />\nFor more information on implementing the live regions, visit https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/ARIA_Live_Regions</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"4.1.3\",\"gigw30\":\"5.2.50\",\"is17802\":\"9.4.1.3\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (462, 'web', 'Invisible content read by screen reader', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are invisible content that are read by screen readers unnecessarily. Examples include:<br />\n- Hidden text on the SSSSS page is still announced.<br />\n<br />\nAs a result, screen reader users get confused by irrelevant content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Use aria-hidden=&quot;true&quot; to hide the background content from the screen reader. Ensure that &quot;aria-hidden&quot; attribute is removed from the page source when user closes the modal dialog.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.2\",\"wcagsuccesscriterianame\":\"Meaningful Sequence\",\"gigw30\":\"5.2.8\",\"is17802\":\"9.1.3.2\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (463, 'web', 'Dragging movement without a single pointer mode of operation', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are dragging functionalities that do not have a single pointer alternative. Examples include:<br />\n- Drag and drop on the SSSSS page only works with mouse.<br />\n<br />\nAs a result, keyboard-only and touch users cannot perform drag actions.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the dragging functionality has a single pointer alternative. <br />\n<br />\nA simple option would be to add buttons to provide a single pointer alternative. Instead of using the dragging movement, users can use the native &lt;button&gt; elements to perform the same functionality.<br />\n<br />\nMake sure that the single pointer alternative can be accessed by those using assistive technologies. For example, make sure the button receives focus and can be activated using a keyboard alone.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment, Visual Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"2.5.7\",\"gigw30\":\"NA\",\"is17802\":\"NA\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (464, 'web', 'Input target lacks sufficient adjacent spacing', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are elements that have target size less than 24x24 pixels in size. Examples include:<br />\n- Small clickable icons on the SSSSS page are below recommended size.<br />\n<br />\nAs a result, users with motor impairments may find them difficult to activate.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that all targets are a minimum of 24 by 24 pixels in size. For best practice, where possible, ensure all targets are a minimum of 44 x 44 pixels in size.<br />\n<br />\nAll pointer input targets must have an area of at least 24 by 24 CSS pixels unless:<br />\n<br />\n* Targets that are under 24 by 24 CSS pixels are positioned so that a 24 CSS pixel diameter circle centred on each target would not intersect with another target or another circle.<br />\n* The function can be achieved through a different control on the same page which meets this requirement.<br />\n* The target is in a block of text or similarly constrained by the line-height of non-target text.<br />\n* The size of the target is not modified by the author and is determined by the user agent.<br />\n* A particular presentation of the target is essential or is legally required for the information being conveyed.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"2.5.8\",\"gigw30\":\"NA\",\"is17802\":\"NA\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (465, 'web', 'Placement of help mechanism  not consistent', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are help mechanisms that are repeated within the set of pages are not in the same relative order programmatically across the pages. Examples include:<br />\n- Help links appear in different orders on the SSSSS pages.<br />\n<br />\nAs a result, users relying on assistive technologies may experience disorientation.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the help mechanism repeated within a set of pages is in the same relative order programmatically across the pages.<br />\n<br />\nAssistive technologies navigate content using the order in which elements appear in the DOM. Make sure that the content is in the same relative order programmatically, and is ordered in such a way that it provides an appropriate reading order.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"3.2.6\",\"gigw30\":\"NA\",\"is17802\":\"NA\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (466, 'web', 'Focused interactive element completely hidden by user opened panels', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are focused interactive elements that are completely hidden by the opened panels. Examples include:<br />\n- The Submit button on the Order page is hidden behind the sidebar panel when it opens.<br />\n<br />\nAs a result, keyboard-only users cannot see or access the button, blocking form submission.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the focused interactive element is at least partially visible in the user&#039;s viewport. As a best practice, ensure that such elements are completely visible when focused.<br />\nAny of the following techniques can be used:<br />\n• Provide a mechanism to bring the focused element into view without moving the keyboard focus. <br />\no A common method is to dismiss the opened panel by Escape key.<br />\no Using keyboard keys to to scroll the content in viewport and bring the focused element into view.<br />\n• Alternatively, allow the opened panel to be dismissed when foused away from it.<br />\n• Another alternative would be to adjust the design of the opened panel<br />\no Reflow the existing content when such panels are opened<br />\no Ensure that the panels open in an empty space on the page and does not overlaps on any focusable element.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"2.4.11\",\"gigw30\":\"NA\",\"is17802\":\"NA\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (467, 'web', 'Focused interactive element completely hidden behind sticky content', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are focused interactive elements that are completely hidden behind the sticky content. Examples include:<br />\n- The Next link on the Checkout page is obscured by the sticky header.<br />\n<br />\nAs a result, keyboard and screen reader users cannot access this link.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the focused interactive element is at least partially visible in the user&#039;s viewport. As a best practice, ensure that such elements are completely visible when focused.<br />\nApply the following changes:<br />\n• To achieve the visibility of focused elements make sure that the focused content in the viewport scrolls up by using scroll padding. For more information, refer https://www.w3.org/TR/css-scroll-snap/#propdef-scroll-padding<br />\n<br />\nAlternatively, restructure the sticky sections as accessible modal dialogs that needs to be dismissed by the user before accessing the background content. For more information, refer https://www.w3.org/WAI/ARIA/apg/patterns/dialog-modal/</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"2.4.11\",\"gigw30\":\"NA\",\"is17802\":\"NA\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (468, 'web', 'Focused interactive element completely hidden behind sticky landmark regions', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are focused interactive elements that are completely hidden behind the sticky landmark regions. Examples include:<br />\n- The Search input on the Home page is hidden behind a sticky navigation landmark.<br />\n<br />\nAs a result, keyboard and screen reader users cannot interact with this input, preventing search functionality.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the focused interactive element is at least partially visible in the user&#039;s viewport. As a best practice, ensure that such elements are completely visible when focused.<br />\nApply the following changes:<br />\n• To achieve the visibility of focused elements make sure that the focused content in the viewport scrolls up by using scroll padding. For more information, refer https://www.w3.org/TR/css-scroll-snap/#propdef-scroll-padding</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Motor Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"2.4.11\",\"gigw30\":\"NA\",\"is17802\":\"NA\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (469, 'web', 'Information previously entered in the same process not auto-populated or available to select', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is information that was entered previously in the same process that is not auto-populated or available to select. Examples include:<br />\n- User address entered in step 1 of the Registration process is not auto-filled in step 3.<br />\n<br />\nAs a result, all users must re-enter data, increasing effort and risk of errors.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Ensure that the previously requested information is either auto-populated or is available for the user to select.<br />\n<br />\nFor this success criterion, using the `autocomplete` attribute alone is not sufficient. While this is required for certain fields under 1.3.5: Identify Input Purpose, using it does not automatically pass this criterion as it relies on the information being stored on the user&#039;s device.<br />\n<br />\nPre-populate the form fields with the previously supplied information. This could be achieved with JavaScript. Allow the user to edit these fields. For example: <br />\n&lt;input type=&quot;text&quot; value=&quot;Pre-populated with information previously provided&quot; ...&gt;<br />\n<br />\nAlternatively, provide the user with a way to select the information, using a component such as a dropdown. Where possible, use a native `&lt;select&gt;`. Make sure that the information available to select is on the same page and is straightforward for the user to locate.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"3.3.7\",\"wcagsuccesscriterianame\":\"Redundant Entry\",\"gigw30\":\"NA\",\"is17802\":\"NA\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (470, 'web', 'Cognitive function test required as step in authentication process', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are authentication processes that require cognitive function tests to complete them. Examples include:<br />\n- CAPTCHA on the Login page requires complex puzzles.<br />\n<br />\nAs a result, users with cognitive disabilities may be unable to complete authentication.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>If a cognitive function test is required, ensure that there is either a mechanism to help users complete it or an alternative authentication method. If this is not possible, ensure that the test is to recognise objects or non-text content provided by the user. <br />\n<br />\nUse native `&lt;input&gt;` elements that support entry using password managers, to reduce the need to memorise passwords. Allow users to copy and paste passwords into the `&lt;input&gt;`. On mobile devices, support the use of biometrics.<br />\n<br />\nAlternatively, provide an alternative method for the user to complete the test. For example, provide a QR code, or verify a login through an email link.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Cognitive Disability\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"AA\",\"wcagsuccesscriteria\":\"3.3.8\",\"gigw30\":\"NA\",\"is17802\":\"NA\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (471, 'web', 'Breadcrumb is programmatically not defined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There is breadcrumb that is not programmatically determined. Examples include:<br />\n- The breadcrumb trail on the Product page is visually shown but lacks ARIA markup.<br />\n<br />\nAs a result, screen reader users cannot navigate or understand the breadcrumb structure.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n• Wrap the breadcrumb links within the &lt;nav&gt; element.<br />\n• Provide a label by using aria-label=&quot;Breadcrumb&quot; that describes the type of navigation provided in the nav element.<br />\n• Markup the set of links using an ordered list, i.e. &lt;ol&gt; and &lt;li&gt;.<br />\n• Add aria-current=&quot;page&quot; to the last link in the set to indicate that it represents the current page.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Major\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (472, 'web', 'Dual functionality for links not operable with keyboard', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>&quot;There are controls in header section that provide dual functions, such as opening a new page and displaying additional menu content, but they rely on mouse hover to reveal extra options and are not operable using the keyboard. Examples include:<br />\n- The &quot;SSSSS&quot; link<br />\n- The &quot;SSSSS&quot; link<br />\n- The &quot;SSSSS&quot; link<br />\n<br />\nAs a result, users who rely on keyboard navigation or screen readers may be unable to access the additional menu options, leading to confusion, navigation errors, or missed content.&quot;</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Avoid adding dual functionality to a single element. If dual functionality is necessary the following changes should be applied:<br />\n- Add an image button using &lt;button&gt; element next to each links serving dual functionality.<br />\n- Specify the name for the &lt;button&gt; element using &#039;aria-label&#039; or &#039;aria-labelledby&#039; attribute.<br />\n- Set &#039;aria-expanded&#039; attribute to &#039;false&#039; for the button by default as the button is in the collapsed state.<br />\n- Update the value of &#039;aria-expanded&#039; attribute to &#039;true&#039; in expanded state on user interaction via scripting.<br />\n- Within the &lt;a&gt; element, add visually hidden text such as &quot;(has more options on next element)&quot; to inform screen reader users that more options are available for the link.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment, Motor Impairment\",\"severity\":\"Critical\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (473, 'web', 'Accordions not operable with a keyboard', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are expandable elements that cannot be expanded or collapsed and/or are not focusable using the keyboard alone. Examples include:<br />\n- The &quot;SSSSS&quot; button in the SSSSS section<br />\n- The &quot;SSSSS&quot; button in the SSSSS section<br />\n- The &quot;SSSSS&quot; button in the SSSSS section<br />\n<br />\nAs a result, keyboard users are blocked from accessing or hiding content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n- Code each accordion header using a &lt;button&gt; element for proper keyboard support and accessibility.<br />\n- Wrap the button in a heading element that maintains the page’s structure. Prefer using native HTML heading tags like &lt;h3&gt;, &lt;h4&gt;, etc. If not feasible, use a container with role=&quot;heading&quot; and assign a meaningful aria-level.<br />\n- The heading container must include only the button. Keep icons or any other persistent elements outside this container.<br />\n- Set aria-expanded on the button to reflect whether the associated panel is visible (true) or hidden (false).<br />\n- Add aria-controls to the button to reference the ID of the corresponding panel content.<br />\n- If the panel is visible and cannot be collapsed, set aria-disabled=&quot;true&quot; on the button.<br />\n- Optionally, apply role=&quot;region&quot; to the panel container and link it to the header button using aria-labelledby for better screen reader navigation. Avoid role=&quot;region&quot; if too many panels are open at once, to prevent landmark overload.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment, Motor Impairment\",\"severity\":\"Blocker\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"2.1.1\",\"wcagsuccesscriterianame\":\"Keyboard\",\"gigw30\":\"5.2.21\",\"is17802\":\"9.2.1.1\"}', '2026-02-06 17:57:20');
INSERT INTO `issue_presets` (`id`, `project_type`, `title`, `description_html`, `metadata_json`, `created_at`) VALUES (474, 'web', 'Missing caption for table', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are tables on the page that do not include a descriptive caption. Without a caption, users—particularly screen reader users—cannot easily understand the purpose or context of the table before navigating its content. This makes it difficult to interpret the data and understand how the table relates to the surrounding information.<br />\n<br />\nAs a result, users relying on assistive technologies may experience confusion and reduced comprehension when interacting with the table.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br />\n- Add a descriptive &lt;caption&gt; to each data table to clearly convey its purpose.<br />\n- Place the caption as the first child of the &lt;table&gt; so screen readers can announce it correctly.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '{\"usersaffected\":\"Visual Impairment\",\"severity\":\"Minor\",\"wcagsuccesscriterialevel\":\"A\",\"wcagsuccesscriteria\":\"1.3.1\",\"wcagsuccesscriterianame\":\"Info and Relationships\",\"gigw30\":\"5.2.7\",\"is17802\":\"9.1.3.1\"}', '2026-02-06 17:57:20');
